(globalThis.TURBOPACK||(globalThis.TURBOPACK=[])).push(["object"==typeof document?document.currentScript:void 0,17914,e=>{e.v(JSON.parse('{"category":"skeleton","version":"1.0.0","questions":[{"id":"skeleton_001","categorySlug":"skeleton","type":"multiple_choice","difficulty":1,"question":"成人の体には骨がおよそいくつあるでしょう？","choices":["約106個","約206個","約306個","約406個"],"correctAnswer":"約206個","hint":"200個台の数字です。赤ちゃんの時はもっと多いんですよ。","explanation":{"summary":"成人の骨の数は約206個。赤ちゃんの時は約300個あり、成長とともに融合して減っていく。","detail":"人間の骨格は約206個の骨で構成されています。しかし、生まれたばかりの赤ちゃんには約300個の骨があります。これは多くの骨がまだ軟骨の状態で分離しているためです。\\n\\n成長するにつれて、これらの軟骨が骨化（ossification）し、隣り合う骨同士が融合していきます。たとえば仙骨は、もともと5つの椎骨が融合してできたものです。骨の融合は25歳頃までに完了します。\\n\\nまた、個人差もあり、過剰骨（accessory bone）を持つ人では206個より多くなることもあります。","funFact":"赤ちゃんの骨は大人より約100個も多い！成長とともに骨がくっついて減っていくなんて、体って不思議。","medicalNote":"骨の数は個人差があります。レントゲンで過剰骨が見つかることは珍しくなく、足部の外脛骨（がいけいこつ）などは10〜20%の人に存在します。","relatedQuestionIds":["skeleton_002","skeleton_005"]},"tags":["骨","数字","基礎知識"],"source":"Gray\'s Anatomy 42nd Edition, Chapter 6","timeLimitSeconds":20,"xpReward":10},{"id":"skeleton_002","categorySlug":"skeleton","type":"true_false","difficulty":1,"question":"人体で最も小さい骨は、耳の中にある「あぶみ骨（stapes）」である。","correctAnswer":"true","hint":"耳の中には音を伝える3つの小さな骨があります。","explanation":{"summary":"あぶみ骨は長さ約3mm、重さ約3mgで人体最小の骨。中耳にあり音の振動を内耳に伝える。","detail":"あぶみ骨（stapes）は中耳に存在する耳小骨のひとつで、長さ約2.5〜3.3mm、重さ約2.5〜3.0mgと、人体で最も小さい骨です。形があぶみ（馬の足をかける器具）に似ていることからこの名前がつきました。\\n\\n耳小骨は3つあり、鼓膜側から「つち骨（malleus）」「きぬた骨（incus）」「あぶみ骨（stapes）」の順に並んでいます。鼓膜の振動をこの3つの骨がテコの原理で約20倍に増幅し、内耳の蝸牛（かぎゅう）に伝えます。\\n\\nこの精巧な増幅メカニズムのおかげで、私たちは空気中のわずかな音の振動を液体で満たされた内耳に効率よく伝達できるのです。","funFact":"人体最小の骨「あぶみ骨」は米粒よりも小さいのに、この骨がなければ私たちは音が聴こえなくなる。","medicalNote":"あぶみ骨の根元が固着する耳硬化症（otosclerosis）は伝音難聴の代表的原因です。あぶみ骨手術（stapedectomy）で劇的に聴力が改善することがあります。","relatedQuestionIds":["skeleton_001"]},"tags":["耳小骨","最小","聴覚"],"source":"Standring S. Gray\'s Anatomy 42nd Ed. Churchill Livingstone, 2020","timeLimitSeconds":20,"xpReward":10},{"id":"skeleton_003","categorySlug":"skeleton","type":"multiple_choice","difficulty":2,"question":"骨の中心部にある「骨髄（こつずい）」の主な役割はどれ？","choices":["骨を硬くする","血液をつくる","カルシウムを吸収する","関節を滑らかにする"],"correctAnswer":"血液をつくる","hint":"白血病の治療で「骨髄移植」が行われる理由を考えてみましょう。","explanation":{"summary":"骨髄は血液細胞の工場。赤血球・白血球・血小板はすべて骨髄でつくられる。","detail":"骨髄（bone marrow）は骨の内部にある柔らかい組織で、造血（血液細胞の産生）という極めて重要な役割を担っています。赤血球、白血球、血小板はすべて骨髄の造血幹細胞（hematopoietic stem cell）から分化してつくられます。\\n\\n骨髄には赤色骨髄と黄色骨髄の2種類があります。赤色骨髄は活発に造血を行い、黄色骨髄は脂肪組織に置き換わったものです。子どもの骨髄はほぼすべて赤色骨髄ですが、成人では椎骨、胸骨、骨盤、肋骨などの骨に限られます。\\n\\n毎日約2000億個もの赤血球がここでつくられており、骨髄はまさに体内最大の「細胞工場」です。","funFact":"骨髄は毎日2000億個もの赤血球を生産する「体内最大の工場」。1秒間に約230万個のペースで新しい赤血球が誕生している。","medicalNote":"骨髄検査（マルク）は白血病や貧血の精密検査で欠かせない手技です。通常は腸骨稜（骨盤の骨）から採取します。","relatedQuestionIds":["skeleton_006"]},"tags":["骨髄","造血","血液"],"source":"Guyton and Hall Textbook of Medical Physiology 14th Ed., Chapter 33","timeLimitSeconds":30,"xpReward":20},{"id":"skeleton_004","categorySlug":"skeleton","type":"multiple_choice","difficulty":2,"question":"人間の背骨（脊柱）は合計いくつの椎骨で構成されている？","choices":["24個","26個","30個","33個"],"correctAnswer":"26個","hint":"頚椎7個、胸椎12個、腰椎5個に加え、融合した仙骨と尾骨があります。","explanation":{"summary":"脊柱は26個の骨（頚椎7+胸椎12+腰椎5+仙骨1+尾骨1）で構成される。ただし分離前は33個。","detail":"脊柱を構成する椎骨は、成人では26個とカウントされます。内訳は頚椎（cervical）7個、胸椎（thoracic）12個、腰椎（lumbar）5個、仙骨（sacrum）1個、尾骨（coccyx）1個です。\\n\\nただし仙骨はもともと5個の仙椎が融合したもの、尾骨は3〜5個の尾椎が融合したものです。そのため融合前の数で数えると33個前後（個人差あり）になります。\\n\\n脊柱は横から見ると美しいS字カーブを描いています。頚椎は前弯、胸椎は後弯、腰椎は前弯、仙骨は後弯です。この二重のS字構造が、歩行時の衝撃を吸収するバネの役割を果たしています。","funFact":"キリンの首の骨の数は人間と同じ7個！あの長い首も椎骨の数は変わらず、1個1個が巨大なだけ。","medicalNote":"腰椎の前弯が過度になった状態を腰椎過前弯（lumbar hyperlordosis）といい、腰痛の原因になります。デスクワーク中心の方は要注意です。","relatedQuestionIds":["skeleton_005","skeleton_008"]},"tags":["脊柱","椎骨","背骨"],"source":"Moore\'s Clinically Oriented Anatomy 9th Ed., Chapter 4","timeLimitSeconds":30,"xpReward":20},{"id":"skeleton_005","categorySlug":"skeleton","type":"fill_in_blank","difficulty":3,"question":"人体で最も長い骨は、太ももにある「＿＿」（大腿骨）である。","correctAnswer":"だいたいこつ","hint":"太ももの骨で、英語ではfemurといいます。","explanation":{"summary":"大腿骨（だいたいこつ/femur）は人体最長の骨で、身長の約1/4の長さがある。","detail":"大腿骨（femur）は人体で最も長く、最も強い骨です。成人では約40〜50cmあり、おおよそ身長の約26%に相当します。法医学では大腿骨の長さから身長を推定する計算式（Trotter & Gleser法など）が用いられます。\\n\\n大腿骨は体重を支える主要な荷重骨であり、その構造は工学的にも注目されています。骨頭から骨幹部にかけての内部構造（骨梁の配列パターン）は、力学的ストレスに最適化されており、これは「ウォルフの法則（Wolff\'s law）」として知られています。\\n\\n骨は荷重がかかる方向に沿って骨梁が発達するため、大腿骨の内部はまるでエッフェル塔のような美しいトラス構造になっています。","funFact":"大腿骨の内部構造はエッフェル塔と同じ力学原理！実はエッフェル塔の設計者が骨の構造を参考にしたという説がある。","medicalNote":"高齢者の大腿骨近位部骨折（特に頚部骨折）は寝たきりの大きな原因です。骨粗鬆症の予防と転倒防止が臨床上極めて重要です。","relatedQuestionIds":["skeleton_001","skeleton_007"]},"tags":["大腿骨","最長","下肢"],"source":"Drake RL. Gray\'s Anatomy for Students 4th Ed., Chapter 6","timeLimitSeconds":30,"xpReward":30},{"id":"skeleton_006","categorySlug":"skeleton","type":"true_false","difficulty":4,"question":"骨は一度完成すると、その後は変化しない静的な組織である。","correctAnswer":"false","hint":"骨折が治るのはなぜでしょう？骨は常に何かが起きています。","explanation":{"summary":"骨は常にリモデリング（破壊と再生）を繰り返す動的な組織。約10年で全身の骨が入れ替わる。","detail":"骨は一見すると硬くて変わらないように見えますが、実は常に「骨リモデリング（bone remodeling）」と呼ばれる新陳代謝を行っている非常にダイナミックな組織です。\\n\\n破骨細胞（osteoclast）が古い骨を溶かし（骨吸収）、骨芽細胞（osteoblast）が新しい骨をつくる（骨形成）。この破壊と再生のサイクルが絶え間なく続いており、成人では約10年で全身の骨がすべて新しいものに入れ替わります。\\n\\nこのリモデリングのバランスが崩れ、骨吸収が骨形成を上回ると骨粗鬆症（osteoporosis）になります。適度な運動による荷重刺激は骨形成を促進するため、骨の健康には運動が欠かせません。","funFact":"あなたの骨は10年前と完全に別モノ！骨は毎日少しずつ壊して作り直されていて、約10年ですべて新品に入れ替わる。","medicalNote":"閉経後の女性はエストロゲン低下により骨吸収が亢進し、急速に骨量が減少します。DEXA検査による骨密度測定と早期介入が重要です。","relatedQuestionIds":["skeleton_003","skeleton_009"]},"tags":["骨リモデリング","骨代謝","破骨細胞"],"source":"Guyton and Hall Textbook of Medical Physiology 14th Ed., Chapter 80","timeLimitSeconds":40,"xpReward":40},{"id":"skeleton_007","categorySlug":"skeleton","type":"multiple_choice","difficulty":4,"question":"骨の強度に関して正しいのはどれ？","choices":["骨はコンクリートとほぼ同じ強度である","骨は同じ重さの鉄筋よりも強い圧縮強度を持つ","骨の強度は年齢によらず一定である","骨は引っ張る力には強いが、圧縮には弱い"],"correctAnswer":"骨は同じ重さの鉄筋よりも強い圧縮強度を持つ","hint":"骨は「生体材料の傑作」と呼ばれるほど優れた力学的特性を持っています。","explanation":{"summary":"骨の圧縮強度は170MPaに達し、同じ重さ（単位重量あたり）で比較すると鉄筋を上回る。","detail":"骨（皮質骨）の圧縮強度は約170MPa（メガパスカル）に達します。鉄筋の圧縮強度は約200〜250MPaですが、鉄の密度（約7.8g/cm³）は骨（約1.8〜2.0g/cm³）の約4倍です。つまり単位重量あたりの強度（比強度）で比較すると、骨は鉄筋を大きく上回ります。\\n\\nこの優れた特性の秘密は骨の複合材料構造にあります。コラーゲン線維（有機質、引っ張り強度を担当）とハイドロキシアパタイト結晶（無機質、圧縮強度を担当）が絶妙に組み合わさることで、軽くて強い理想的な構造材料が実現しています。\\n\\nこの構造は炭素繊維強化プラスチック（CFRP）と同じ原理であり、航空宇宙工学のバイオミメティクス（生体模倣）研究の対象にもなっています。","funFact":"骨は同じ重さで比べると鉄より強い！しかも折れても自分で修復できる。人工物にはまだ真似できない究極のスマート材料。","medicalNote":"骨の強度はコラーゲンの質と石灰化の度合いに依存します。ステロイド長期使用ではコラーゲン合成が抑制され、骨密度が正常でも骨折リスクが上昇します。","relatedQuestionIds":["skeleton_005","skeleton_006"]},"tags":["骨強度","生体力学","材料科学"],"source":"Currey JD. Bones: Structure and Mechanics. Princeton University Press, 2002","timeLimitSeconds":40,"xpReward":40},{"id":"skeleton_008","categorySlug":"skeleton","type":"multiple_choice","difficulty":4,"question":"頭蓋骨の縫合線（suture）が存在する主な理由として最も適切なのはどれ？","choices":["脳への酸素供給経路を確保するため","出産時に頭蓋骨を変形させて産道を通過するため","外傷時に衝撃を分散させるため","頭皮への血液供給を行うため"],"correctAnswer":"出産時に頭蓋骨を変形させて産道を通過するため","hint":"新生児の頭に「大泉門（だいせんもん）」というやわらかい部分があるのは有名ですね。","explanation":{"summary":"頭蓋縫合は出産時の頭蓋変形と出生後の脳の急速な成長を可能にするための構造。","detail":"新生児の頭蓋骨は複数の骨が縫合線（suture）と泉門（fontanelle）によって分離されています。これにより出産時に頭蓋骨が互いに重なり合うように変形し（molding）、狭い産道を通過することが可能になります。\\n\\n出生後も縫合線は脳の急速な成長に対応するために開いたままです。脳は生後2年で出生時の約3倍の大きさになりますが、縫合線があることで頭蓋骨はこの急成長に追従して拡大できます。大泉門は生後12〜18か月頃、小泉門は生後2〜3か月頃に閉鎖します。\\n\\n縫合線の早期癒合（頭蓋縫合早期癒合症/craniosynostosis）が起こると、脳の成長が妨げられ頭蓋内圧亢進や頭蓋変形を引き起こすことがあります。","funFact":"赤ちゃんの頭のてっぺんにある柔らかい「大泉門」は、出産という人生最初の大冒険を乗り越えるための精巧なデザイン。","medicalNote":"乳児健診では大泉門の状態を必ず確認します。膨隆は頭蓋内圧亢進、陥凹は脱水のサインです。閉鎖時期の異常は縫合早期癒合症を疑います。","relatedQuestionIds":["skeleton_004","skeleton_010"]},"tags":["頭蓋骨","縫合","発達"],"source":"Moore KL. The Developing Human 11th Ed., Chapter 14","timeLimitSeconds":40,"xpReward":40},{"id":"skeleton_009","categorySlug":"skeleton","type":"true_false","difficulty":5,"question":"宇宙飛行士は宇宙に長期滞在すると、1か月あたり約1〜2%の骨密度を失う。","correctAnswer":"true","hint":"地球上では重力が骨に荷重をかけています。無重力ではどうなるでしょう？","explanation":{"summary":"無重力環境では骨への荷重刺激がなくなり、月1〜2%の骨密度低下が起こる。これは骨粗鬆症患者の年間損失に匹敵する。","detail":"国際宇宙ステーション（ISS）での長期滞在研究によると、宇宙飛行士は荷重骨（大腿骨、脛骨、腰椎など）で月あたり約1〜1.5%の骨密度低下を示します。これは閉経後骨粗鬆症の患者が1年間に失う量に匹敵する驚くべき速度です。\\n\\nウォルフの法則（Wolff\'s law）に基づき、骨は力学的負荷に応じてリモデリングされます。無重力環境では荷重刺激が消失するため、破骨細胞による骨吸収が優位になり急速に骨量が減少します。\\n\\nNASAはこの対策として、ISSに抵抗運動装置（ARED: Advanced Resistive Exercise Device）を搭載し、宇宙飛行士に毎日2時間以上の運動を義務付けています。火星有人探査（片道約9か月）に向け、骨量維持は最重要課題のひとつです。","funFact":"宇宙に半年いると骨密度が約10%減少！地球に戻っても完全回復に2〜3年かかる。火星旅行の最大の敵は、実は自分の骨。","medicalNote":"寝たきりの患者さんでも同様の廃用性骨萎縮が起こります。早期離床・荷重訓練の重要性は宇宙医学の知見からも裏付けられています。","relatedQuestionIds":["skeleton_006","skeleton_007"]},"tags":["宇宙医学","骨密度","骨粗鬆症"],"source":"Lang T et al. J Bone Miner Res. 2004;19(6):1006-12","timeLimitSeconds":45,"xpReward":50},{"id":"skeleton_010","categorySlug":"skeleton","type":"fill_in_blank","difficulty":5,"question":"骨に力学的ストレスが加わるとその方向に骨が強化されるという法則を「＿＿の法則」という。","correctAnswer":"ウォルフ","hint":"19世紀ドイツの解剖学者の名前です。英語ではWolff\'s lawと呼ばれます。","explanation":{"summary":"ウォルフの法則（Wolff\'s law）は、骨が力学的負荷に適応してリモデリングされるという生体力学の基本原理。","detail":"ウォルフの法則（Wolff\'s law, 1892年）は、ドイツの外科医ユリウス・ウォルフ（Julius Wolff）が提唱した法則で、「骨はそこにかかる力学的負荷に応じて内部構造と外部形態を適応的に変化させる」という原理です。\\n\\nこの法則の分子メカニズムが解明されたのは比較的最近のことです。骨細胞（osteocyte）は骨の中に張り巡らされた細管ネットワーク（骨小管/canaliculi）を通じて力学的ストレスを感知するメカノセンサーとして機能しています。荷重による骨内の間質液流動を感知し、Wntシグナリング経路やスクレロスチン（sclerostin）の発現調整を介して骨形成を制御します。\\n\\nこの原理は臨床的にも極めて重要で、骨粗鬆症治療における運動療法の科学的根拠であり、人工関節設計におけるストレスシールディング問題の理論的背景でもあります。","funFact":"テニス選手の利き腕の骨は反対側より最大40%も太い！骨は使えば使うほど強くなる「筋トレできる臓器」。","medicalNote":"抗スクレロスチン抗体（ロモソズマブ）はウォルフの法則の分子機構を応用した骨粗鬆症治療薬です。骨形成促進と骨吸収抑制の二重作用を持ちます。","relatedQuestionIds":["skeleton_006","skeleton_009"]},"tags":["ウォルフの法則","生体力学","骨リモデリング"],"source":"Wolff J. Das Gesetz der Transformation der Knochen, 1892; Robling AG et al. J Biol Chem. 2008;283(9):5866-5875","timeLimitSeconds":45,"xpReward":50}]}'))},27132,e=>{e.v(JSON.parse('{"category":"muscle","version":"1.0.0","questions":[{"id":"muscle_001","categorySlug":"muscle","type":"multiple_choice","difficulty":1,"question":"人間の体にはおよそいくつの筋肉があるでしょう？","choices":["約200個","約400個","約600個","約800個"],"correctAnswer":"約600個","hint":"骨の数（約206個）の約3倍です。","explanation":{"summary":"人体には約600個の骨格筋があり、体重の約40%を占める。","detail":"人体には約600個の骨格筋（skeletal muscle）が存在し、体重の約40〜45%（男性）または約35〜40%（女性）を占めています。これに加えて心筋（cardiac muscle）と平滑筋（smooth muscle）もありますが、一般的に「筋肉」と呼ぶ場合は骨格筋を指します。\\n\\n骨格筋は随意筋（自分の意思で動かせる筋肉）であり、骨に付着して関節をまたぐことで体を動かします。一方、心筋と平滑筋は不随意筋（自分の意思では動かせない筋肉）で、心臓の拍動や消化管の蠕動運動などを行います。\\n\\n最も大きい骨格筋は大殿筋（gluteus maximus）、最も小さいのは耳のあぶみ骨筋（stapedius）で長さわずか約1mmです。","funFact":"体重60kgの人なら約24kgが筋肉！体の中で最も重い「臓器」は、実は筋肉。","medicalNote":"サルコペニア（加齢性筋肉減少症）は高齢者のフレイル・転倒の主因です。40歳以降、年約1%ずつ筋肉量が減少するため、早期からの筋力トレーニングが重要です。","relatedQuestionIds":["muscle_002","muscle_005"]},"tags":["筋肉","数字","基礎知識"],"source":"Standring S. Gray\'s Anatomy 42nd Ed., Chapter 5","timeLimitSeconds":20,"xpReward":10},{"id":"muscle_002","categorySlug":"muscle","type":"true_false","difficulty":1,"question":"心臓は筋肉でできている。","correctAnswer":"true","hint":"心臓は一生休まずに動き続けるポンプです。何でできていると思いますか？","explanation":{"summary":"心臓は心筋（cardiac muscle）という特殊な筋肉でできており、一生涯にわたって自動的に収縮し続ける。","detail":"心臓は心筋（cardiac muscle）という特殊な横紋筋で構成されています。心筋は骨格筋と同じく横紋（しまもよう）を持ちますが、大きく異なる特徴があります。\\n\\n第一に、心筋は不随意筋であり、自律神経の支配は受けるものの自分の意思では動かせません。第二に、心筋細胞同士は介在板（intercalated disc）という特殊な結合で繋がっており、電気信号が細胞間を高速で伝わります。これにより心臓全体が協調して収縮できます。\\n\\n第三に、心筋には自動能（automaticity）があります。洞結節（SA node）のペースメーカー細胞が自発的に電気信号を発生させるため、心臓は脳からの指令がなくても拍動し続けます。心臓移植後の心臓が動くのもこの自動能のおかげです。","funFact":"心臓は一生で約30億回拍動する！しかも脳からの命令なしに自分で動ける、唯一の「自立した筋肉」。","medicalNote":"心筋は再生能力が極めて低いため、心筋梗塞で壊死した心筋は線維化して瘢痕になります。iPS細胞由来心筋細胞シートの研究が進んでいます。","relatedQuestionIds":["muscle_001","muscle_008"]},"tags":["心筋","心臓","不随意筋"],"source":"Guyton and Hall Textbook of Medical Physiology 14th Ed., Chapter 9","timeLimitSeconds":20,"xpReward":10},{"id":"muscle_003","categorySlug":"muscle","type":"multiple_choice","difficulty":2,"question":"筋肉痛が運動の翌日〜2日後に起こる現象を何という？","choices":["急性筋肉痛","遅発性筋肉痛（DOMS）","筋膜炎","横紋筋融解症"],"correctAnswer":"遅発性筋肉痛（DOMS）","hint":"英語の略称はDOMSです。Delayed Onset Muscle Sorenessの頭文字です。","explanation":{"summary":"遅発性筋肉痛（DOMS: Delayed Onset Muscle Soreness）は運動後24〜72時間に出現する筋肉痛で、主に伸張性収縮で起こる。","detail":"遅発性筋肉痛（DOMS）は、慣れない運動や激しい運動の後24〜72時間後にピークを迎える筋肉の痛みや凝りです。特に伸張性収縮（eccentric contraction：筋肉が伸びながら力を出す動き）で顕著に発生します。階段を下りる、坂道を下る、ゆっくりダンベルを下ろすなどの動作が代表例です。\\n\\nDOMSのメカニズムは長年「乳酸蓄積説」が信じられてきましたが、現在では否定されています。現在の主流理論は、伸張性収縮による筋線維の微細損傷（Z線の断裂など）が炎症反応を引き起こし、ブラジキニンやプロスタグランジンなどの発痛物質が痛覚受容器を刺激するというものです。\\n\\n重要なのは、DOMSは筋肉の適応過程の一部であり、同じ運動を繰り返すと「繰り返し効果（repeated bout effect）」により徐々に軽減されるという点です。","funFact":"筋肉痛の原因は「乳酸」ではなかった！実は筋線維の微細な損傷と炎症反応が原因。長年の常識が覆された。","medicalNote":"通常のDOMSは数日で自然軽快しますが、運動後に尿が茶褐色になった場合は横紋筋融解症を疑い、直ちに受診が必要です。","relatedQuestionIds":["muscle_006","muscle_009"]},"tags":["DOMS","筋肉痛","運動生理学"],"source":"Cheung K et al. Sports Med. 2003;33(2):145-64","timeLimitSeconds":30,"xpReward":20},{"id":"muscle_004","categorySlug":"muscle","type":"multiple_choice","difficulty":2,"question":"人体で最も強い力を発揮する筋肉はどれ？","choices":["大殿筋","咬筋（こうきん）","大腿四頭筋","広背筋"],"correctAnswer":"咬筋（こうきん）","hint":"食べ物を噛む時に使う筋肉です。小さいけれど驚くほど強い力を出します。","explanation":{"summary":"咬筋（masseter）は断面積あたりの力が最大で、最大約70〜100kgの咬合力を生む。","detail":"「最も強い筋肉」の定義は複数ありますが、単位断面積あたりの力（比筋力）で見ると、咬筋（masseter）が人体最強です。咬筋は顎の閉口運動を担い、側頭筋や内側翼突筋と協調して最大約70〜100kgf（一部の測定では約120kgf）の咬合力を発揮します。\\n\\n咬筋がこれほど強力なのは、短い筋線維が多数並列に配列した羽状筋（pennate muscle）構造を持つためです。この配列は速度よりも力の発揮に有利で、小さな体積で大きな力を生み出せます。\\n\\n一方、「最も大きな力」を出す筋肉は大腿四頭筋、「最も大きな仕事量」を出す筋肉は大殿筋です。筋力の「最強」は評価基準によって変わるのです。","funFact":"人間の噛む力は最大100kg超！体重以上の力を小さな咬筋が生み出している。歯ぎしりで歯が割れるのも納得。","medicalNote":"夜間の歯ぎしり（ブラキシズム）では咬筋の過活動により咬合力が通常の数倍になることがあります。顎関節症や歯の破折の原因となるため、マウスピースが有効です。","relatedQuestionIds":["muscle_001","muscle_005"]},"tags":["咬筋","最強","咬合力"],"source":"Tortora GJ. Principles of Anatomy and Physiology 16th Ed., Chapter 11","timeLimitSeconds":30,"xpReward":20},{"id":"muscle_005","categorySlug":"muscle","type":"fill_in_blank","difficulty":3,"question":"筋肉が収縮する仕組みを説明する理論を「＿＿説」（sliding filament theory）という。","correctAnswer":"滑り説","hint":"アクチンとミオシンという2つのフィラメントが「滑る」ように動きます。","explanation":{"summary":"滑り説（sliding filament theory）は、アクチンフィラメントがミオシンフィラメントの間を滑り込むことで筋収縮が起こるという理論。","detail":"滑り説（sliding filament theory）は1954年にHuxley AFとNiedergerke R、およびHuxley HEとHanson Jの2つのグループが独立に提唱しました。この理論では、筋収縮はフィラメント自体が短縮するのではなく、細いアクチンフィラメントが太いミオシンフィラメントの間に滑り込むことで起こると説明します。\\n\\n分子レベルでは、ミオシン頭部（クロスブリッジ）がATPのエネルギーを使ってアクチンに結合し、首振り運動（power stroke）を行います。このサイクルが繰り返されることで、アクチンフィラメントがサルコメア（筋節）の中央へ引き込まれ、サルコメアが短縮して筋肉が収縮します。\\n\\n1つの筋線維には数千個のサルコメアが直列に並んでおり、それぞれが同時に短縮することで、マクロな筋収縮が生み出されます。","funFact":"筋肉の収縮は分子のミクロな「綱引き」！ミオシンがアクチンをたぐり寄せる動きを毎秒数百回繰り返している。","medicalNote":"悪性高熱症ではリアノジン受容体の異常によりカルシウムが制御不能に放出され、筋の持続収縮と高体温が起こります。全身麻酔時の致死的合併症として要注意です。","relatedQuestionIds":["muscle_008","muscle_010"]},"tags":["滑り説","アクチン","ミオシン","筋収縮"],"source":"Huxley AF, Niedergerke R. Nature. 1954;173:971-973; Huxley HE, Hanson J. Nature. 1954;173:973-976","timeLimitSeconds":30,"xpReward":30},{"id":"muscle_006","categorySlug":"muscle","type":"true_false","difficulty":4,"question":"筋トレで筋肉が太くなるのは、筋線維の「数」が増えるからである。","correctAnswer":"false","hint":"筋線維の数と太さ、どちらが変化するのか考えてみましょう。","explanation":{"summary":"筋トレによる筋肥大は主に筋線維の「太さ」が増す肥大（hypertrophy）であり、筋線維の数が増える増殖（hyperplasia）ではない。","detail":"筋力トレーニングによる筋肥大のメカニズムは、主に既存の筋線維が太くなる「筋肥大（hypertrophy）」です。筋線維の数が増える「筋増殖（hyperplasia）」はヒトではほとんど起こらないとされています。\\n\\nトレーニングによる筋線維の微細損傷は、衛星細胞（satellite cell）を活性化します。衛星細胞は筋線維の表面にある幹細胞で、損傷した筋線維に融合して核を提供し、タンパク質合成能力を高めます。これにより筋原線維の数とサイズが増加し、筋線維が太くなります。\\n\\nmTOR（mechanistic target of rapamycin）経路は筋タンパク質合成の中心的なシグナル伝達経路であり、機械的刺激（トレーニング）、アミノ酸（栄養）、成長因子（IGF-1など）によって活性化されます。","funFact":"筋トレで筋肉が太くなるのは、筋線維の数が増えるのではなく、1本1本が太くなるから。筋線維の数は生まれた時にほぼ決まっている。","medicalNote":"筋ジストロフィーでは筋線維が変性・壊死し、衛星細胞による再生が追いつかなくなります。筋線維が脂肪や結合組織に置換される偽性肥大が特徴的です。","relatedQuestionIds":["muscle_003","muscle_005"]},"tags":["筋肥大","筋トレ","衛星細胞"],"source":"Schoenfeld BJ. J Strength Cond Res. 2010;24(10):2857-72","timeLimitSeconds":40,"xpReward":40},{"id":"muscle_007","categorySlug":"muscle","type":"multiple_choice","difficulty":4,"question":"筋肉のエネルギー源として、最初の数秒間で使われるのはどれ？","choices":["ブドウ糖（グルコース）","クレアチンリン酸（CP）","脂肪酸","乳酸"],"correctAnswer":"クレアチンリン酸（CP）","hint":"全力ダッシュの最初の数秒間は、すぐにATPを再合成できる物質が使われます。","explanation":{"summary":"筋収縮の最初の数秒間はクレアチンリン酸（CP）がATPを瞬時に再合成する。持続時間は約8〜10秒。","detail":"筋肉のエネルギー供給には3つのシステムがあり、運動の強度と持続時間によって使い分けられます。\\n\\n第1のシステムがATP-CP系（ホスファゲン系）です。筋肉中に蓄えられたクレアチンリン酸（phosphocreatine）がクレアチンキナーゼの触媒によりADPにリン酸基を転移し、瞬時にATPを再合成します。この反応は酸素不要で最速ですが、持続時間は約8〜10秒に限られます。100m走や重量挙げなどの超短時間・高強度運動で主役を務めます。\\n\\n第2は解糖系（30秒〜2分）、第3は酸化的リン酸化系（有酸素系、2分以上）です。実際にはこれらのシステムは完全に切り替わるのではなく、常に並行して稼働しており、運動強度に応じて主役が入れ替わります。","funFact":"100m走のウサイン・ボルトが9.58秒で走れるのは、クレアチンリン酸の持続時間（約10秒）とほぼ一致！人間の瞬発力の限界は体内の化学反応で決まっている。","medicalNote":"クレアチンサプリメントは筋肉内CP量を増加させ、高強度運動のパフォーマンスを向上させるエビデンスがあります。腎機能正常者では安全性が確認されています。","relatedQuestionIds":["muscle_005","muscle_010"]},"tags":["エネルギー代謝","ATP","クレアチンリン酸"],"source":"McArdle WD. Exercise Physiology 8th Ed., Chapter 5","timeLimitSeconds":40,"xpReward":40},{"id":"muscle_008","categorySlug":"muscle","type":"multiple_choice","difficulty":4,"question":"死後に筋肉が硬直する「死後硬直（rigor mortis）」の直接的な原因はどれ？","choices":["筋肉の水分が失われるため","ATPが枯渇しミオシンがアクチンから離れなくなるため","筋肉中のタンパク質が変性するため","神経からの刺激が停止するため"],"correctAnswer":"ATPが枯渇しミオシンがアクチンから離れなくなるため","hint":"筋肉が弛緩するにもエネルギーが必要です。そのエネルギーがなくなったらどうなる？","explanation":{"summary":"死後、ATP合成が停止するとミオシンがアクチンから解離できなくなり、筋肉が硬直する。これが死後硬直の本質。","detail":"筋収縮のクロスブリッジサイクルでは、ミオシン頭部がアクチンから離れる（解離する）ステップにATPの結合が必須です。生きている間はATPが継続的に供給されるため、筋肉は収縮と弛緩を繰り返せます。\\n\\n死後、代謝が停止してATP合成が止まると、ミオシン頭部はアクチンに結合したまま（いわゆるrigor complex）離れることができなくなります。これがすべての筋線維で同時に起こることで、全身の筋肉が硬直します。\\n\\n死後硬直は通常死後2〜4時間で始まり、12〜24時間でピークに達します。その後、自己融解（autolysis）により筋タンパク質が分解されて硬直は徐々に解けていきます。法医学では死後硬直の進行度が死亡時刻推定の手がかりとなります。","funFact":"「力を抜く」にもATPというエネルギーが必要！筋肉はリラックスするのにもエネルギーを使う。死ぬとATPが尽きて体が硬くなる。","medicalNote":"全身麻酔でサクシニルコリンを投与した際に起こる悪性高熱症も、筋小胞体からのCa²⁺大量放出→持続的筋収縮→体温上昇というATP消費の暴走が本態です。","relatedQuestionIds":["muscle_005","muscle_002"]},"tags":["死後硬直","ATP","法医学"],"source":"Tortora GJ. Principles of Anatomy and Physiology 16th Ed., Chapter 10; DiMaio VJ. Forensic Pathology 2nd Ed.","timeLimitSeconds":40,"xpReward":40},{"id":"muscle_009","categorySlug":"muscle","type":"true_false","difficulty":5,"question":"速筋線維（Type II）は遅筋線維（Type I）よりもミトコンドリアが多い。","correctAnswer":"false","hint":"マラソンランナーと短距離ランナー、どちらがミトコンドリア（有酸素エネルギー工場）を多く必要とするでしょう？","explanation":{"summary":"遅筋線維（Type I）の方がミトコンドリアが多く、有酸素代謝に優れる。速筋線維（Type II）は解糖系に依存する。","detail":"骨格筋の筋線維は大きく遅筋線維（Type I、赤筋）と速筋線維（Type II、白筋）に分類されます。\\n\\n遅筋線維（Type I）は豊富なミトコンドリアとミオグロビン（酸素貯蔵タンパク質）を持ち、酸化的リン酸化によるATP産生に優れています。持久力に富み、マラソンなどの長時間運動で主役を務めます。赤い色はミオグロビンとチトクロームによるものです。\\n\\n速筋線維（Type II）はミトコンドリアが少なく、解糖系によるATP産生に依存します。収縮速度と発揮張力が大きいですが、疲労しやすいという特徴があります。100m走やジャンプなどの瞬発的運動に適しています。\\n\\nType IIはさらにType IIa（中間型、ある程度有酸素能力あり）とType IIx（最も解糖依存）に細分されます。トレーニングによりType IIx→Type IIaへの変換は起こりますが、Type I⇔Type IIの変換は基本的に起こらないとされています。","funFact":"マグロの赤身は遅筋（赤筋）、ヒラメの白身は速筋（白筋）。魚の身の色の違いは、まさに筋線維タイプの違い！","medicalNote":"加齢に伴い速筋線維（Type II）が選択的に萎縮するため、高齢者はとっさの動きが苦手になります。転倒予防にはパワートレーニング（速い動きの筋トレ）が有効です。","relatedQuestionIds":["muscle_007","muscle_006"]},"tags":["筋線維タイプ","遅筋","速筋","ミトコンドリア"],"source":"Bottinelli R, Reggiani C. Prog Biophys Mol Biol. 2000;73(2-4):195-262","timeLimitSeconds":45,"xpReward":50},{"id":"muscle_010","categorySlug":"muscle","type":"fill_in_blank","difficulty":5,"question":"筋収縮の引き金となるイオンは「＿＿イオン」で、筋小胞体から放出されてトロポニンに結合する。","correctAnswer":"カルシウム","hint":"元素記号はCa。骨にも多く含まれるミネラルです。","explanation":{"summary":"カルシウムイオン（Ca²⁺）が筋小胞体から放出されてトロポニンCに結合し、アクチン上のミオシン結合部位を露出させることで筋収縮が始まる。","detail":"筋収縮の興奮収縮連関（excitation-contraction coupling）は、以下のステップで進行します。\\n\\n1. 運動神経からのインパルスが神経筋接合部でアセチルコリンを放出\\n2. 筋細胞膜に活動電位が発生し、T管（横行小管）を伝播\\n3. T管のジヒドロピリジン受容体（DHPR）が筋小胞体のリアノジン受容体（RyR）を活性化\\n4. 筋小胞体からCa²⁺が大量に放出（安静時の約100倍の濃度に上昇）\\n5. Ca²⁺がトロポニンC（TnC）に結合\\n6. トロポニン-トロポミオシン複合体の構造変化により、アクチン上のミオシン結合部位が露出\\n7. ミオシン頭部がアクチンに結合し、クロスブリッジサイクルが開始\\n\\n弛緩時にはSERCA（筋小胞体Ca²⁺-ATPase）がATPを使ってCa²⁺を筋小胞体に回収し、トロポニンからCa²⁺が離れることでミオシン結合部位が再び遮蔽されます。","funFact":"筋収縮のスイッチはカルシウム！骨を強くするだけでなく、すべての動きの起点となる。体内で最も多用途なミネラル。","medicalNote":"低カルシウム血症ではテタニー（筋の持続収縮・痙攣）が起こります。一方、ダントロレンは筋小胞体からのCa²⁺放出を抑制する薬剤で、悪性高熱症の特効薬です。","relatedQuestionIds":["muscle_005","muscle_008"]},"tags":["カルシウム","興奮収縮連関","トロポニン","筋小胞体"],"source":"Bers DM. Excitation-Contraction Coupling and Cardiac Contractile Force. Springer, 2001; Guyton and Hall 14th Ed., Chapter 7","timeLimitSeconds":45,"xpReward":50}]}'))},99396,e=>{e.v(JSON.parse('{"category":"circulatory","version":"1.0.0","questions":[{"id":"circulatory_001","categorySlug":"circulatory","type":"true_false","difficulty":1,"question":"心臓は1日に約10万回拍動している。","correctAnswer":"true","hint":"1分間に約70回拍動すると考えてみよう。","explanation":{"summary":"心臓は1日に約10万回、一生で約30億回拍動する。","detail":"安静時の心拍数は成人で1分間に60〜100回程度です。仮に1分間に70回とすると、1時間で4,200回、1日で約10万回になります。\\n\\n生まれてから80年間休みなく動き続けると、一生で約30億回も拍動する計算です。心臓は体の中で最も働き者の臓器と言えるでしょう。\\n\\n心臓の筋肉（心筋）は骨格筋と違い、自律的にリズムを刻む「自動能」を持っています。これは洞結節（どうけっせつ）というペースメーカー細胞のおかげです。","funFact":"心臓が一生で送り出す血液の量は、約2億リットル。大型タンカー1隻分に相当する!","medicalNote":"赤ちゃんの心拍数は大人の2倍近い120〜160回/分。聴診器で聴くと、まるで小さな馬が駆けているような速さです。成長とともにゆっくりになっていきますよ。","relatedQuestionIds":["circulatory_002","circulatory_004"]},"tags":["心臓","心拍数","基礎知識"],"source":"Guyton and Hall Textbook of Medical Physiology, 14th Edition","timeLimitSeconds":20,"xpReward":10},{"id":"circulatory_002","categorySlug":"circulatory","type":"multiple_choice","difficulty":1,"question":"血液が全身を一周するのにかかる時間は、およそどのくらい?","choices":["約10秒","約1分","約5分","約30分"],"correctAnswer":"約1分","hint":"意外と速い! マラソン選手の1kmタイムより短いよ。","explanation":{"summary":"血液は約1分で全身を一周する。","detail":"心臓から送り出された血液は、大動脈を通って全身の毛細血管まで届き、静脈を通って心臓に戻ってきます。この一周にかかる時間は安静時で約50秒〜1分です。\\n\\n運動時には心拍出量が増えるため、さらに速くなります。激しい運動中は約20秒で一周することもあります。\\n\\n血管を全てつなぎ合わせると、その長さは約10万km。地球を2周半できる距離です。この長大な管の中を、血液はわずか1分で駆け抜けているのです。","funFact":"全身の血管を一列につなげると約10万km。地球2周半の距離を、血液はたった1分で旅している!","medicalNote":"ショック状態（大量出血など）では、血液の循環時間が延長します。指先の毛細血管を押して離した時、色が戻るまでの時間（CRT: Capillary Refill Time）が2秒以上かかると、循環不全のサインです。","relatedQuestionIds":["circulatory_001","circulatory_006"]},"tags":["血液循環","血管","基礎知識"],"source":"Ganong\'s Review of Medical Physiology, 26th Edition","timeLimitSeconds":20,"xpReward":10},{"id":"circulatory_003","categorySlug":"circulatory","type":"multiple_choice","difficulty":2,"question":"赤血球の寿命はおよそ何日?","choices":["約7日","約30日","約120日","約365日"],"correctAnswer":"約120日","hint":"季節が一つ変わるくらいの期間だよ。","explanation":{"summary":"赤血球の寿命は約120日（約4ヶ月）で、古くなると脾臓で分解される。","detail":"赤血球は骨髄で作られ、約120日間血液中を循環した後、主に脾臓（ひぞう）で分解されます。成人の体内には約25兆個の赤血球があり、毎秒約200万個が新しく作られています。\\n\\n赤血球は成熟する過程で核を失うため、自己修復ができません。120日間ひたすら酸素を運び続け、最後は形が崩れて脾臓のフィルターに引っかかり、マクロファージに食べられます。\\n\\n分解されたヘモグロビンの鉄はリサイクルされ、新しい赤血球に再利用されます。体はとてもエコなシステムを持っているのです。","funFact":"赤血球1個の中にはヘモグロビンが約2億7000万個! 酸素を運ぶために究極まで最適化された「酸素宅配便」だ。","medicalNote":"赤ちゃんが生まれた直後は胎児ヘモグロビン（HbF）が多く、これは酸素との親和性が高い特別仕様。お母さんの胎盤から効率よく酸素をもらうための仕組みです。生後数ヶ月かけて成人型ヘモグロビン（HbA）に置き換わります。","relatedQuestionIds":["circulatory_005","circulatory_007"]},"tags":["赤血球","血液","骨髄"],"source":"Williams Hematology, 10th Edition","timeLimitSeconds":30,"xpReward":20},{"id":"circulatory_004","categorySlug":"circulatory","type":"fill_in_blank","difficulty":3,"question":"心臓には4つの部屋があり、上の2つを「＿＿」、下の2つを「心室」と呼ぶ。","correctAnswer":"心房","hint":"「房」は部屋という意味。心臓の上の部屋は血液を「受け取る」役割だよ。","explanation":{"summary":"心臓の上の2部屋は「心房（しんぼう）」で、血液を受け取る役割を持つ。","detail":"心臓は右心房・右心室・左心房・左心室の4つの部屋に分かれています。心房（Atrium）は血液を受け取る部屋で、心室（Ventricle）は血液を送り出す部屋です。\\n\\n右心房は全身から戻ってきた静脈血を受け取り、右心室に送ります。右心室は血液を肺に送り出します（肺循環）。左心房は肺から戻ってきた酸素豊富な血液を受け取り、左心室が全身に送り出します（体循環）。\\n\\n左心室の壁は右心室の約3倍の厚さがあります。全身に血液を送るという大仕事に対応するため、筋肉が発達しているのです。","funFact":"心臓の「心房」の英語「Atrium」は、古代ローマの家の中庭の名前が由来。血液が集まる「中庭」のような場所、というわけだ!","medicalNote":"お腹の中の赤ちゃんは肺で呼吸していないので、右心房と左心房の間に「卵円孔（らんえんこう）」という穴が開いています。生まれて最初の呼吸をすると、この穴は自然に閉じます。まさに誕生の瞬間に心臓が「切り替わる」のです。","relatedQuestionIds":["circulatory_001","circulatory_006"]},"tags":["心臓","心房","心室","解剖学"],"source":"Netter\'s Atlas of Human Anatomy, 8th Edition","timeLimitSeconds":30,"xpReward":30},{"id":"circulatory_005","categorySlug":"circulatory","type":"true_false","difficulty":3,"question":"動脈には常に酸素の多い血液が、静脈には常に酸素の少ない血液が流れている。","correctAnswer":"false","hint":"肺に向かう血管と肺から戻る血管のことを考えてみよう。","explanation":{"summary":"肺動脈には酸素の少ない血液が、肺静脈には酸素の多い血液が流れており、例外がある。","detail":"「動脈＝酸素が多い」「静脈＝酸素が少ない」と思いがちですが、これは正確ではありません。動脈と静脈の本当の定義は、**心臓から出る血管が動脈、心臓に戻る血管が静脈**です。\\n\\n肺動脈は心臓（右心室）から肺へ向かう血管なので「動脈」ですが、中を流れるのは酸素が少ない静脈血です。逆に、肺静脈は肺から心臓（左心房）に戻る血管なので「静脈」ですが、肺で酸素を受け取った動脈血が流れています。\\n\\nこの肺循環の「逆転現象」は、多くの医学生がつまずくポイントです。","funFact":"解剖学の教科書では動脈を赤、静脈を青で描くが、実際の静脈血は暗い赤色。「血管が青く見える」のは皮膚を通した光の散乱による錯覚!","medicalNote":"赤ちゃんに多い先天性心疾患の中には、動脈血と静脈血が混ざってしまうものがあります。例えば心室中隔欠損症（VSD）では、左心室の酸素豊富な血液が右心室に流れ込みます。新生児健診での心雑音チェックはとても大切です。","relatedQuestionIds":["circulatory_003","circulatory_004"]},"tags":["動脈","静脈","肺循環","体循環"],"source":"Guyton and Hall Textbook of Medical Physiology, 14th Edition","timeLimitSeconds":30,"xpReward":30},{"id":"circulatory_006","categorySlug":"circulatory","type":"multiple_choice","difficulty":4,"question":"心臓の拍動リズムを自律的に生み出している場所はどこ?","choices":["房室結節（AVノード）","洞結節（SAノード）","ヒス束","プルキンエ線維"],"correctAnswer":"洞結節（SAノード）","hint":"心臓の「天然ペースメーカー」と呼ばれる場所だよ。右心房の上部にあるよ。","explanation":{"summary":"洞結節（SAノード）は右心房にある「天然のペースメーカー」で、心拍リズムの起点。","detail":"洞結節（洞房結節、SA node）は右心房の上部、上大静脈の開口部付近にある小さな組織です。ここには特殊な心筋細胞が集まっており、外部からの刺激がなくても自発的に電気信号を発生させます。\\n\\n洞結節が発生させた電気信号は、まず心房全体に広がり心房を収縮させます。次に房室結節（AV node）で約0.1秒遅延された後、ヒス束→脚→プルキンエ線維を通って心室全体に伝わり、心室を収縮させます。\\n\\nこの精密な刺激伝導系のおかげで、心房と心室が絶妙なタイミングで収縮し、効率よく血液を送り出すことができるのです。","funFact":"洞結節の細胞はわずか数千個しかないのに、25兆個の赤血球を全身に送り出す心臓の司令塔。体内で最も影響力のある「少数精鋭チーム」だ!","medicalNote":"洞結節の機能が低下すると「洞不全症候群」となり、脈が極端に遅くなったり、めまい・失神を起こすことがあります。人工ペースメーカーはこの洞結節の代わりに電気信号を送る装置です。最新の「リードレスペースメーカー」はカプセル大で、心臓の中に直接留置できます。","relatedQuestionIds":["circulatory_001","circulatory_008"]},"tags":["洞結節","刺激伝導系","ペースメーカー","電気生理学"],"source":"Braunwald\'s Heart Disease, 12th Edition","timeLimitSeconds":40,"xpReward":40},{"id":"circulatory_007","categorySlug":"circulatory","type":"multiple_choice","difficulty":4,"question":"血液凝固（止血）の過程で、傷ついた血管に最初に集まるのはどれ?","choices":["赤血球","白血球","血小板","フィブリン"],"correctAnswer":"血小板","hint":"「板」という字がつく、血液の中で最も小さい細胞成分だよ。","explanation":{"summary":"止血の第一段階では血小板が傷口に集まり「血小板血栓」を形成する。","detail":"止血は3段階で進みます。\\n\\n**第1段階（一次止血）**: 血管が傷つくと、露出したコラーゲンに血小板が付着し、活性化されて次々と集まります（血小板凝集）。数分以内に「血小板血栓（白色血栓）」が形成され、一時的に出血を止めます。\\n\\n**第2段階（二次止血）**: 凝固因子のカスケード反応が起こり、最終的にフィブリンという網目状のタンパク質が作られます。フィブリンが血小板血栓を補強し、しっかりとした「フィブリン血栓」が完成します。\\n\\n**第3段階（線溶）**: 傷が治ると、プラスミンという酵素がフィブリンを分解し、血栓を溶かして血管を元通りにします。","funFact":"血小板は実は「細胞」ではなく、巨核球という巨大細胞のかけら。1個の巨核球から数千個の血小板が生まれる、究極の「分身の術」!","medicalNote":"赤ちゃんは出生時、ビタミンKが不足しているため血液が固まりにくい状態です。そのため、生まれてすぐ・生後1週間・生後1ヶ月にビタミンKシロップを投与します。これは「新生児ビタミンK欠乏性出血症」を予防するとても大切な処置です。","relatedQuestionIds":["circulatory_003","circulatory_009"]},"tags":["血小板","止血","凝固","血液"],"source":"Robbins & Cotran Pathologic Basis of Disease, 10th Edition","timeLimitSeconds":40,"xpReward":40},{"id":"circulatory_008","categorySlug":"circulatory","type":"true_false","difficulty":4,"question":"心臓は自身の筋肉に栄養を送るための専用の血管（冠動脈）を持っている。","correctAnswer":"true","hint":"心臓の中に血液がたくさん流れているけど、心筋はそこから直接栄養をもらえるわけではないよ。","explanation":{"summary":"心臓は冠動脈（冠状動脈）という専用の血管から酸素と栄養を受け取っている。","detail":"心臓の内側には大量の血液が流れていますが、心筋は心腔内の血液から直接酸素を受け取ることはほとんどできません。心筋が厚すぎて、内側からの拡散だけでは足りないのです。\\n\\nそこで、大動脈の付け根から左右2本の冠動脈（冠状動脈）が枝分かれし、心臓の表面を冠（かんむり）のように覆いながら、心筋全体に酸素と栄養を届けています。「冠動脈」の名前は、この冠のような形に由来します。\\n\\n興味深いことに、冠動脈への血流は心臓が「休んでいる」拡張期に多くなります。収縮期には心筋が血管を圧迫するためです。心臓は「働いている時ではなく、休んでいる時に栄養をもらう」という、少し皮肉な仕組みです。","funFact":"心臓は体重の0.5%しかないのに、全身の酸素の約5%を消費する「大食い臓器」。燃費の悪さはスーパーカー並み!","medicalNote":"冠動脈が詰まると心筋梗塞になります。胸の中央が締めつけられるような痛み、冷や汗、吐き気がある場合は、すぐに救急車を呼んでください。発症から治療までの時間が命を左右します。「Time is Muscle（時間が心筋を救う）」と言われています。","relatedQuestionIds":["circulatory_006","circulatory_002"]},"tags":["冠動脈","心筋","心臓","虚血性心疾患"],"source":"Braunwald\'s Heart Disease, 12th Edition","timeLimitSeconds":40,"xpReward":40},{"id":"circulatory_009","categorySlug":"circulatory","type":"fill_in_blank","difficulty":5,"question":"胎児の血液循環では、肺を迂回するために肺動脈と大動脈をつなぐ「＿＿」という血管が存在する。","correctAnswer":"動脈管","hint":"ラテン語では「Ductus arteriosus」。生後に自然に閉鎖する「ボタル管」とも呼ばれるよ。","explanation":{"summary":"動脈管（ボタル管）は胎児期に肺動脈と大動脈をつなぎ、出生後に閉鎖する特殊な血管。","detail":"胎児はお母さんの胎盤から酸素をもらっているため、肺で呼吸する必要がありません。そのため、右心室から肺動脈に送り出された血液の大部分は、肺を通らずに動脈管（Ductus arteriosus）を経由して大動脈に流れ込みます。\\n\\n出生後、赤ちゃんが最初の呼吸をすると肺が膨らみ、肺血管の抵抗が急激に低下します。同時に、臍帯が切断されることで体循環の抵抗が上昇し、血流の方向が変わります。動脈管は通常、生後24〜72時間以内に収縮して機能的に閉鎖し、数週間で完全に線維化して「動脈管索」という痕跡になります。\\n\\nこの閉鎖のトリガーは主に酸素濃度の上昇とプロスタグランジンの低下です。","funFact":"人間の赤ちゃんは生まれた瞬間に、心臓の血流パターンが胎児型から成人型に「大転換」する。この劇的な循環の切り替えは、わずか数分で完了する生命の奇跡!","medicalNote":"早産児では動脈管が閉じにくい「動脈管開存症（PDA）」がしばしば見られます。特に在胎28週未満の超早産児では高頻度です。インドメタシンやイブプロフェンなどのプロスタグランジン合成阻害薬で治療することが多いですが、閉じない場合はカテーテル治療や手術が必要になることもあります。","relatedQuestionIds":["circulatory_004","circulatory_005"]},"tags":["胎児循環","動脈管","新生児","先天性心疾患"],"source":"Nelson Textbook of Pediatrics, 21st Edition","timeLimitSeconds":45,"xpReward":50},{"id":"circulatory_010","categorySlug":"circulatory","type":"multiple_choice","difficulty":5,"question":"フランク・スターリングの法則（Frank-Starling law）が説明しているのは、次のうちどれ?","choices":["心拍数が上がると血圧が上昇する関係","心室に流入する血液量が増えると、心臓の収縮力が増す関係","血管が細くなると血流速度が上がる関係","運動時に冠動脈が拡張する関係"],"correctAnswer":"心室に流入する血液量が増えると、心臓の収縮力が増す関係","hint":"心筋が引き伸ばされるほど、縮む力も強くなるという法則だよ。ゴムバンドを想像してみて。","explanation":{"summary":"フランク・スターリングの法則は「心室への流入血液量（前負荷）が増えると拍出量も増える」という心臓の基本原理。","detail":"フランク・スターリングの法則は、心臓生理学の最も重要な法則の一つです。心室に戻ってくる血液量（前負荷/Preload）が増えると、心室壁が引き伸ばされ、それに応じて収縮力が増して拍出量（Stroke Volume）が増加します。\\n\\nこれはゴムバンドを引っ張るほど、戻る力が強くなるのと似た原理です。分子レベルでは、心筋のサルコメア（筋節）が最適な長さに伸びることで、アクチンとミオシンのフィラメントの重なりが最適化され、より強い収縮が得られます。\\n\\nこの法則により、左右の心室の拍出量は自動的にバランスが取れます。もし右心室が少し多く血液を送り出すと、左心室への流入が増え、左心室の拍出量も自動的に増加するのです。","funFact":"この法則を発見したOtto FrankとErnest Starlingは面識がなかった。別々の国で同じ発見をした、まさに科学の「シンクロニシティ」!","medicalNote":"心不全ではこの法則が破綻します。弱った心臓は血液が多く流入しても十分に収縮できず、心室内に血液がたまって肺うっ血（息切れ）や浮腫（むくみ）を引き起こします。心不全治療の利尿薬は、この過剰な前負荷を減らすことで症状を改善します。","relatedQuestionIds":["circulatory_006","circulatory_008"]},"tags":["フランク・スターリングの法則","心臓生理学","前負荷","心拍出量"],"source":"Guyton and Hall Textbook of Medical Physiology, 14th Edition","timeLimitSeconds":45,"xpReward":50}]}'))},32833,e=>{e.v(JSON.parse('{"category":"respiratory","version":"1.0.0","questions":[{"id":"respiratory_001","categorySlug":"respiratory","type":"multiple_choice","difficulty":1,"question":"人は1日に約何回呼吸している?","choices":["約2,000回","約5,000回","約20,000回","約100,000回"],"correctAnswer":"約20,000回","hint":"1分間に約12〜20回呼吸していることから計算してみよう。","explanation":{"summary":"成人は1日に約2万回呼吸し、約1万リットルの空気を吸い込んでいる。","detail":"安静時の呼吸回数は成人で1分間に12〜20回程度です。1分間に15回とすると、1時間で900回、1日で約2万回になります。\\n\\n1回の呼吸で約500mLの空気を吸い込むので、1日に吸い込む空気の量は約1万リットル。これは大きな浴槽50杯分に相当します。\\n\\nこの膨大な空気から、肺は酸素を効率よく取り込んでいます。吸い込む空気の酸素濃度は約21%ですが、吐き出す空気でも約16%の酸素が残っています。実は、吸った酸素の約1/4しか体に取り込んでいないのです。","funFact":"吐く息にまだ16%の酸素が残っているからこそ、人工呼吸（口対口）で相手に酸素を届けられる。呼吸の「おすそ分け」が命を救う!","medicalNote":"赤ちゃんの呼吸回数は大人の2〜3倍で、1分間に30〜60回。速くて浅い呼吸が正常です。急に呼吸が速くなったり、肋骨の間がへこむ「陥没呼吸」が見られたら、呼吸が苦しいサイン。すぐに医療機関を受診してください。","relatedQuestionIds":["respiratory_002","respiratory_004"]},"tags":["呼吸","呼吸回数","基礎知識"],"source":"Ganong\'s Review of Medical Physiology, 26th Edition","timeLimitSeconds":20,"xpReward":10},{"id":"respiratory_002","categorySlug":"respiratory","type":"true_false","difficulty":1,"question":"右の肺は3つ、左の肺は2つの「葉（よう）」に分かれている。","correctAnswer":"true","hint":"左側には心臓があるため、左の肺は少し小さいよ。","explanation":{"summary":"右肺は上葉・中葉・下葉の3葉、左肺は上葉・下葉の2葉に分かれている。","detail":"肺は左右で形が異なります。右肺は上葉・中葉・下葉の3つの葉に、左肺は上葉・下葉の2つの葉に分かれています。\\n\\n左肺が2葉しかないのは、心臓が胸の中央よりやや左寄りにあるためです。左肺には心臓が収まるための「心切痕（しんせっこん）」というくぼみがあり、その分だけ右肺より約10%小さくなっています。\\n\\nこの左右非対称な構造のため、誤嚥（ごえん：食べ物などが気道に入ること）した異物は右の気管支に入りやすい傾向があります。右の気管支は左より太く、角度が急なためです。","funFact":"左肺にある心臓用のくぼみ「心切痕」には、「舌」に似た小さな突起（肺小舌）がある。肺にも「舌」があるなんて!","medicalNote":"お子さんがピーナッツやおもちゃの小さい部品を飲み込んでしまった場合（気道異物）、右の気管支に入ることが多いです。急な咳き込みや喘鳴（ぜんめい：ゼーゼー音）が続く場合は、気道異物の可能性があります。3歳未満のお子さんにはピーナッツなどの豆類は与えないようにしましょう。","relatedQuestionIds":["respiratory_001","respiratory_005"]},"tags":["肺","解剖学","肺葉"],"source":"Gray\'s Anatomy for Students, 4th Edition","timeLimitSeconds":20,"xpReward":10},{"id":"respiratory_003","categorySlug":"respiratory","type":"multiple_choice","difficulty":2,"question":"肺の中で酸素と二酸化炭素の交換が行われる、ブドウの房のような小さな袋を何と呼ぶ?","choices":["気管支","肺胞（はいほう）","胸膜","横隔膜"],"correctAnswer":"肺胞（はいほう）","hint":"「胞」は小さな袋の意味。英語では「Alveolus」と言うよ。","explanation":{"summary":"肺胞はガス交換の最小単位で、両肺合わせて約3〜5億個存在する。","detail":"肺胞（Alveolus）は直径約0.2〜0.3mmの小さな袋状の構造で、肺の末端に位置しています。両肺合わせて約3〜5億個あり、その表面積を全て広げるとテニスコート約1面分（約70平方メートル）にもなります。\\n\\n肺胞の壁は非常に薄く（約0.5μm）、その周囲を毛細血管が網目のように取り囲んでいます。酸素はこの薄い壁を通って血液に入り、二酸化炭素は血液から肺胞内に出ていきます。このガス交換はわずか0.3秒で完了します。\\n\\n肺胞の内側には「サーファクタント（肺表面活性物質）」という液体が薄く広がっており、肺胞がつぶれるのを防いでいます。","funFact":"肺胞の壁の薄さはわずか0.5μm。サランラップ（約10μm）の1/20! この究極の薄さが、効率的なガス交換を可能にしている。","medicalNote":"早産児ではサーファクタント（肺表面活性物質）の産生が未熟なため、肺胞がつぶれてしまう「新生児呼吸窮迫症候群（RDS）」を起こすことがあります。現在は人工サーファクタントを気管内に投与する治療法があり、早産児の生存率を劇的に改善しました。","relatedQuestionIds":["respiratory_004","respiratory_006"]},"tags":["肺胞","ガス交換","解剖学"],"source":"West\'s Respiratory Physiology: The Essentials, 11th Edition","timeLimitSeconds":30,"xpReward":20},{"id":"respiratory_004","categorySlug":"respiratory","type":"fill_in_blank","difficulty":3,"question":"血液中の酸素を運ぶ赤いタンパク質は「＿＿」で、鉄を含んでいる。","correctAnswer":"ヘモグロビン","hint":"「ヘモ」は血液、「グロビン」はタンパク質の意味。英語では「Hemoglobin」だよ。","explanation":{"summary":"ヘモグロビンは赤血球中の酸素運搬タンパク質で、鉄原子が酸素と結合する。","detail":"ヘモグロビン（Hemoglobin, Hb）は赤血球の中に存在するタンパク質で、4つのサブユニット（α2β2）からなります。各サブユニットには「ヘム」という鉄を含む構造があり、この鉄原子に酸素分子が1つずつ結合します。つまり、ヘモグロビン1分子で最大4つの酸素分子を運べます。\\n\\n面白いことに、1つ目の酸素が結合すると、ヘモグロビンの形が変わって2つ目以降の酸素が結合しやすくなります。これを「協同効果（Cooperativity）」と呼び、酸素の多い肺で効率よく酸素を取り込む仕組みです。\\n\\n逆に、酸素の少ない組織では酸素を放しやすくなります。このS字型の「酸素解離曲線」は、ヘモグロビンの精巧なデザインを示しています。","funFact":"ヘモグロビンの赤い色は鉄が酸素と結びついた色。錆びた鉄が赤いのと同じ原理! つまり、血が赤いのは「鉄が錆びている」からだ。","medicalNote":"一酸化炭素（CO）はヘモグロビンとの親和性が酸素の約250倍もあります。CO中毒では、ヘモグロビンがCOで占拠されて酸素を運べなくなります。冬場の石油ストーブやガス機器の不完全燃焼にはくれぐれもご注意を。お子さんは大人より体が小さいため、CO中毒の影響を受けやすいです。","relatedQuestionIds":["respiratory_003","respiratory_007"]},"tags":["ヘモグロビン","酸素運搬","赤血球","鉄"],"source":"Harper\'s Illustrated Biochemistry, 31st Edition","timeLimitSeconds":30,"xpReward":30},{"id":"respiratory_005","categorySlug":"respiratory","type":"true_false","difficulty":3,"question":"くしゃみの時に出る空気の速度は、時速160km以上になることがある。","correctAnswer":"true","hint":"新幹線の速さに匹敵するかも...?","explanation":{"summary":"くしゃみの風速は時速160km以上に達し、飛沫は数メートル先まで飛ぶことがある。","detail":"くしゃみは、鼻腔の異物を排除するための爆発的な呼気反射です。くしゃみ時の空気の速度は時速160km（約44m/秒）以上に達することがあり、これは大型台風の風速やプロテニス選手のサーブの速度に匹敵します。\\n\\n1回のくしゃみで約4万個の飛沫が放出され、大きな飛沫は1〜2m先まで、微小な飛沫（エアロゾル）は最大8m先まで到達する可能性があるという研究報告があります。\\n\\nくしゃみのメカニズムは、まず鼻腔の刺激が三叉神経を通じて脳幹の「くしゃみ中枢」に伝えられ、反射的に深い吸気の後、声門が閉じた状態で胸腔内圧が急激に上昇し、一気に開放されるというものです。","funFact":"くしゃみを我慢して鼻と口を完全に塞ぐと、胸腔内圧が急上昇して鼓膜損傷や眼窩骨折を起こした例が報告されている。くしゃみは止めないで!","medicalNote":"くしゃみや咳のエチケットは感染症予防の基本です。手のひらではなく、肘の内側で口と鼻を覆う「肘ブロック」を教えてあげましょう。手のひらで受けると、その手で触ったものにウイルスが付着して広がります。","relatedQuestionIds":["respiratory_001","respiratory_003"]},"tags":["くしゃみ","防御反射","飛沫","感染予防"],"source":"JAMA Internal Medicine; MIT fluid dynamics research (Bourouiba et al., 2014)","timeLimitSeconds":30,"xpReward":30},{"id":"respiratory_006","categorySlug":"respiratory","type":"multiple_choice","difficulty":4,"question":"肺胞でのガス交換において、酸素と二酸化炭素が移動する物理的な仕組みは次のうちどれ?","choices":["能動輸送（ATPを使う）","浸透圧による移動","拡散（濃度差による移動）","線毛運動による輸送"],"correctAnswer":"拡散（濃度差による移動）","hint":"香水を開けると部屋中に匂いが広がるのと同じ原理だよ。エネルギーは使わない。","explanation":{"summary":"肺胞でのガス交換は「拡散」で行われ、濃度の高い方から低い方へ自然に移動する。","detail":"肺胞でのガス交換は、**拡散（Diffusion）**という物理現象によって行われます。分子は濃度の高い方から低い方へ自然に移動するという単純な原理です。エネルギー（ATP）は一切必要ありません。\\n\\n肺胞内の酸素分圧（約100mmHg）は毛細血管の静脈血の酸素分圧（約40mmHg）より高いため、酸素は肺胞から血液へ拡散します。逆に、静脈血の二酸化炭素分圧（約46mmHg）は肺胞内（約40mmHg）より高いため、二酸化炭素は血液から肺胞へ拡散します。\\n\\nフィックの拡散法則によれば、ガス交換の効率は「面積×濃度差÷厚さ」に比例します。肺胞はテニスコート1面分の面積と極薄の壁（0.5μm）で、この効率を最大化しているのです。","funFact":"肺胞のガス交換にかかる時間はわずか0.25秒。赤血球が肺胞の毛細血管を通過する0.75秒のうち、最初の1/3で交換は完了する。余裕しゃくしゃく!","medicalNote":"肺炎や間質性肺疾患では肺胞の壁が厚くなり（フィックの法則の「厚さ」が増加）、ガス交換の効率が低下します。興味深いことに、二酸化炭素は酸素より約20倍拡散しやすいため、軽度の肺疾患では酸素だけが低下し、二酸化炭素は正常に保たれることが多いです。","relatedQuestionIds":["respiratory_003","respiratory_004"]},"tags":["ガス交換","拡散","肺胞","呼吸生理学"],"source":"West\'s Respiratory Physiology: The Essentials, 11th Edition","timeLimitSeconds":40,"xpReward":40},{"id":"respiratory_007","categorySlug":"respiratory","type":"multiple_choice","difficulty":4,"question":"血液中の二酸化炭素の大部分（約70%）は、どの形で運ばれている?","choices":["ヘモグロビンに結合した状態","血漿に溶けた状態","重炭酸イオン（HCO3-）の形","炭酸（H2CO3）の形"],"correctAnswer":"重炭酸イオン（HCO3-）の形","hint":"赤血球内の酵素（炭酸脱水酵素）が、CO2を別の物質に変換しているよ。","explanation":{"summary":"血中CO2の約70%は重炭酸イオン（HCO3-）として、約20%はヘモグロビンに結合して、約10%は溶存CO2として運搬される。","detail":"二酸化炭素（CO2）の血液中での運搬には3つの形態があります。\\n\\n**1. 重炭酸イオン（HCO3-）: 約70%**\\nCO2は赤血球に入ると、炭酸脱水酵素（Carbonic Anhydrase）の作用で水と反応し、炭酸（H2CO3）を経て重炭酸イオン（HCO3-）と水素イオン（H+）に分解されます。HCO3-は赤血球から血漿に出て運搬されます。\\n\\n**2. カルバミノ化合物: 約20〜23%**\\nCO2はヘモグロビンのアミノ基に直接結合し、カルバミノヘモグロビンとして運搬されます。\\n\\n**3. 溶存CO2: 約7〜10%**\\n少量のCO2はそのまま血漿に溶けて運搬されます。\\n\\n肺に到達すると、これらの反応が逆向きに進み、CO2が遊離して肺胞から排出されます。","funFact":"炭酸脱水酵素は体内で最も速い酵素の一つで、1秒間に100万回もの反応を触媒する。CO2運搬の「超高速変換装置」だ!","medicalNote":"重炭酸イオン（HCO3-）は血液のpH緩衝系（バッファーシステム）としても重要です。血液のpHは7.35〜7.45の狭い範囲に保たれており、この範囲から外れると「アシドーシス」や「アルカローシス」と呼ばれる危険な状態になります。呼吸の速さを変えることでCO2排出量を調整し、pHをコントロールしています。","relatedQuestionIds":["respiratory_004","respiratory_006"]},"tags":["二酸化炭素","重炭酸イオン","ガス運搬","炭酸脱水酵素"],"source":"Guyton and Hall Textbook of Medical Physiology, 14th Edition","timeLimitSeconds":40,"xpReward":40},{"id":"respiratory_008","categorySlug":"respiratory","type":"true_false","difficulty":4,"question":"呼吸のリズムは、主に血液中の二酸化炭素濃度の変化によってコントロールされている。","correctAnswer":"true","hint":"酸素が減った時より、CO2が増えた時の方が体は敏感に反応するよ。","explanation":{"summary":"呼吸中枢は血中CO2濃度（正確にはpH）の変化に最も敏感に反応し、呼吸を調節している。","detail":"直感的には「酸素が足りなくなったら呼吸が速くなる」と思いがちですが、実際には**血液中のCO2濃度の上昇（=pHの低下）**が呼吸促進の最も強力な刺激です。\\n\\n脳幹にある呼吸中枢（延髄の背側・腹側呼吸群、橋の呼吸調節中枢）は、脳脊髄液のpH変化を感知する中枢化学受容体と、頸動脈体・大動脈体にある末梢化学受容体からの情報を統合して呼吸を調節しています。\\n\\n血中CO2が1mmHg上昇するだけで、換気量は約2〜3L/分増加します。一方、酸素分圧は60mmHg以下に低下しないと換気量の著明な増加は起こりません。つまり、体はCO2の変化に対して酸素の変化より遥かに敏感なのです。","funFact":"息を止めていられなくなるのは、酸素が減ったからではなくCO2が溜まったから。過呼吸でCO2を減らしてから息を止めると長く止められるが、酸素不足で意識を失う危険があるので絶対にやらないで!","medicalNote":"重度のCOPD（慢性閉塞性肺疾患）の一部の患者さんでは、慢性的にCO2が高いため、呼吸のドライブが「低酸素」に依存するようになっています（CO2ナルコーシスのリスク）。このような方に高濃度の酸素を投与すると、呼吸ドライブが低下して危険です。酸素投与には医師の適切な管理が必要です。","relatedQuestionIds":["respiratory_006","respiratory_007"]},"tags":["呼吸調節","化学受容体","二酸化炭素","呼吸中枢"],"source":"West\'s Respiratory Physiology: The Essentials, 11th Edition","timeLimitSeconds":40,"xpReward":40},{"id":"respiratory_009","categorySlug":"respiratory","type":"fill_in_blank","difficulty":5,"question":"肺胞の内側を覆い、表面張力を低下させて肺胞の虚脱を防ぐ物質を「＿＿」と呼ぶ。","correctAnswer":"サーファクタント","hint":"英語で「Surface Active Agent（表面活性物質）」の略語が名前の由来だよ。肺胞II型細胞が産生する。","explanation":{"summary":"肺サーファクタントはII型肺胞上皮細胞が産生するリン脂質で、表面張力を下げて肺胞の安定性を保つ。","detail":"肺サーファクタント（Pulmonary Surfactant）は、II型肺胞上皮細胞が産生する脂質とタンパク質の混合物です。主成分はジパルミトイルホスファチジルコリン（DPPC）というリン脂質で、肺胞の内側の空気-水界面に薄い膜を形成します。\\n\\nサーファクタントがなければ、ラプラスの法則（P=2T/r）により小さな肺胞ほど高い圧力が生じ、小さな肺胞の空気が大きな肺胞に移動して虚脱（無気肺）が起こります。サーファクタントは表面張力を大幅に低下させ（約70mN/mから約25mN/m以下に）、さらに肺胞が小さくなるほど表面張力をより大きく低下させる性質があるため、異なるサイズの肺胞を安定に共存させます。\\n\\nサーファクタントの産生は在胎約24週頃から始まり、34〜36週で十分な量に達します。","funFact":"サーファクタントは呼吸のたびに圧縮・伸展を繰り返す「動的な膜」。もしサーファクタントがなければ、1回の呼吸に必要なエネルギーは5〜10倍に増え、呼吸するだけでヘトヘトになる!","medicalNote":"サーファクタント欠乏による新生児呼吸窮迫症候群（RDS）は、かつては早産児の主要な死因でした。1980年代に藤原哲郎教授（日本）が世界で初めて人工サーファクタントの臨床使用に成功し、世界中の早産児の命を救いました。日本発の新生児医療における最大の貢献の一つです。","relatedQuestionIds":["respiratory_003","respiratory_006"]},"tags":["サーファクタント","肺胞","表面張力","新生児医療"],"source":"West\'s Respiratory Physiology: The Essentials, 11th Edition; Fujiwara et al., Lancet 1980","timeLimitSeconds":45,"xpReward":50},{"id":"respiratory_010","categorySlug":"respiratory","type":"multiple_choice","difficulty":5,"question":"換気血流比（V/Qミスマッチ）について正しいのはどれ?","choices":["立位の肺では、肺尖部の換気血流比は肺底部より低い","立位の肺では、肺尖部の換気血流比は肺底部より高い","正常肺では換気と血流は全ての部位で完全に一致している","換気血流比は体位によって変化しない"],"correctAnswer":"立位の肺では、肺尖部の換気血流比は肺底部より高い","hint":"重力の影響で、血流は肺の下の方に多く集まるよ。換気も下の方が多いけど、血流ほどの差はない。","explanation":{"summary":"立位では重力により肺底部の血流が増加するが、換気の増加はそれほどでないため、肺尖部のV/Q比は高く、肺底部は低くなる。","detail":"肺でのガス交換の効率を理解するには、換気（V: Ventilation）と血流（Q: Perfusion）の比率、すなわちV/Q比が重要です。理想的にはV/Q=1.0ですが、実際の肺では部位によって大きく異なります。\\n\\n立位の肺では、重力の影響で血流は肺底部に偏ります。血液は水と同様に下に集まるためです。換気も肺底部の方が多いですが、血流ほどの差はありません。結果として:\\n\\n- **肺尖部**: V/Q比 ≒ 3.3（換気過剰・血流不足 → 「換気の無駄使い」に近い）\\n- **肺底部**: V/Q比 ≒ 0.6（血流過剰・換気不足 → ガス交換効率がやや低い）\\n- **肺中部**: V/Q比 ≒ 1.0（最もバランスが良い）\\n\\nこのV/Qミスマッチが、健常人でも肺胞気-動脈血酸素分圧較差（A-aDO2）が完全にゼロにならない理由の一つです。","funFact":"無重力の宇宙では重力によるV/Qミスマッチがなくなるため、理論上はガス交換効率が向上する。宇宙飛行士の肺は地上より「高性能」かも!","medicalNote":"肺塞栓症（エコノミークラス症候群）では、血栓で血流が遮断された領域のV/Q比が無限大（換気はあるが血流ゼロ = 死腔）になります。一方、重症肺炎では炎症で換気ができない領域のV/Q比がゼロ（血流はあるが換気なし = シャント）になります。V/Q比の異常が低酸素血症の主要な原因です。","relatedQuestionIds":["respiratory_006","respiratory_008"]},"tags":["換気血流比","V/Qミスマッチ","呼吸生理学","ガス交換"],"source":"West\'s Respiratory Physiology: The Essentials, 11th Edition","timeLimitSeconds":45,"xpReward":50}]}'))},59800,e=>{e.v(JSON.parse('{"category":"digestive","version":"1.0.0","questions":[{"id":"digestive_001","categorySlug":"digestive","type":"multiple_choice","difficulty":1,"question":"食べ物を飲み込んだあと、胃に届くまでに通る管の名前は？","choices":["気管","食道","大動脈","胆管"],"correctAnswer":"食道","hint":"「食べ物の道」と書きます。","explanation":{"summary":"食道は口と胃をつなぐ約25cmの筋肉の管です。","detail":"食道（esophagus）は、のどの奥から胃の入り口までをつなぐ長さ約25cmの管です。食べ物は重力だけで胃に落ちるわけではなく、食道の壁にある筋肉が波のように収縮する「蠕動運動（ぜんどううんどう）」によって押し進められます。\\n\\nこの仕組みのおかげで、逆立ちしていても食べ物は胃に届きます。宇宙飛行士が無重力空間で食事できるのも蠕動運動のおかげです。\\n\\n食道の入り口と出口にはそれぞれ括約筋があり、食べ物が逆流しないようにガードしています。このガードが弱くなると胃酸が逆流し、「逆流性食道炎」の原因になります。","funFact":"逆立ちしても食べ物が胃に届くのは、食道の蠕動運動のおかげ。宇宙でも食事ができる理由はこれ！","medicalNote":"おかもん先生：赤ちゃんは食道の括約筋が未熟なので、ミルクを吐き戻しやすいんです。授乳後のゲップはとても大切ですよ。","relatedQuestionIds":["digestive_002"]},"tags":["食道","蠕動運動","消化管"],"source":"Gray\'s Anatomy 42nd Edition; Guyton and Hall Textbook of Medical Physiology 14th Edition","timeLimitSeconds":20,"xpReward":10},{"id":"digestive_002","categorySlug":"digestive","type":"true_false","difficulty":1,"question":"胃酸は金属も溶かすほど強い酸である。","correctAnswer":"true","hint":"胃酸のpHは1〜2。レモン汁よりもずっと強い酸です。","explanation":{"summary":"胃酸（塩酸）のpHは1〜2で、鉄やアルミニウムなどの金属を溶かす力があります。","detail":"胃の壁細胞（parietal cell）から分泌される胃酸は、主成分が塩酸（HCl）で、pH 1〜2という非常に強い酸性を示します。これはレモン汁（pH 2程度）やお酢（pH 2.5程度）よりも強く、薄い鉄板やカミソリの刃さえ溶かすことができます。\\n\\nでは、なぜ胃自身は溶けないのでしょうか？ それは胃の粘膜が「粘液-重炭酸バリア」と呼ばれる防御層を持っているからです。胃の表面の粘液細胞が厚さ約0.5mmの粘液層を分泌し、同時に重炭酸イオンを放出してpHを中性に近づけています。\\n\\n胃粘膜は約3〜5日で完全に新しい細胞に入れ替わり、常にフレッシュな状態を保っています。この驚くべき自己修復能力が、私たちの胃を守っているのです。","funFact":"胃酸はカミソリの刃を溶かせるほど強力。でも胃は3〜5日で粘膜が全部入れ替わるから、自分自身は溶けない！","medicalNote":"おかもん先生：ストレスや薬（NSAIDs等）で粘液バリアが弱まると胃潰瘍になります。お子さんの腹痛が続くときは「ストレス性胃炎」の可能性も考えてくださいね。","relatedQuestionIds":["digestive_001"]},"tags":["胃酸","胃","pH","粘膜防御"],"source":"Guyton and Hall Textbook of Medical Physiology 14th Edition; Ganong\'s Review of Medical Physiology 26th Edition","timeLimitSeconds":20,"xpReward":10},{"id":"digestive_003","categorySlug":"digestive","type":"true_false","difficulty":2,"question":"肝臓は人体で最も大きい内臓である。","correctAnswer":"true","hint":"体重の約2〜3%を占め、右のあばら骨の下に位置しています。","explanation":{"summary":"肝臓は成人で約1.2〜1.5kgあり、人体で最も大きい内臓臓器です。","detail":"肝臓（liver）は成人で約1.2〜1.5kgの重さがあり、体内で最大の内臓臓器です（皮膚を臓器とみなすと皮膚が最大ですが、内臓に限ると肝臓が最大）。右上腹部のあばら骨に守られるように位置しています。\\n\\n肝臓は「体内の化学工場」と呼ばれ、500種類以上の機能を担っています。代表的なものは：栄養素の代謝と貯蔵、胆汁の生成、有害物質の解毒、タンパク質（アルブミンや凝固因子）の合成、免疫機能への関与などです。\\n\\n驚くべきことに、肝臓は全体の70%を切除しても数か月で元の大きさに再生できます。この再生能力は臓器の中で群を抜いており、生体肝移植（健康な人の肝臓の一部を患者に移植する手術）を可能にしています。ギリシャ神話でプロメテウスの肝臓が毎日再生する話は、古代の人々がこの再生能力を知っていた可能性を示唆しています。","funFact":"肝臓は70%切り取っても数か月で元通りに再生する！生体肝移植が可能なのはこの驚異の再生力のおかげ。","medicalNote":"おかもん先生：新生児黄疸は、生まれたばかりの赤ちゃんの肝臓がビリルビン処理にまだ慣れていないために起こります。多くは生理的なもので自然に改善しますが、長引く場合は受診してくださいね。","relatedQuestionIds":["digestive_005"]},"tags":["肝臓","臓器","再生"],"source":"Gray\'s Anatomy 42nd Edition; Sherlock\'s Diseases of the Liver and Biliary System 13th Edition","timeLimitSeconds":30,"xpReward":20},{"id":"digestive_004","categorySlug":"digestive","type":"multiple_choice","difficulty":3,"question":"小腸の長さは成人でおよそどのくらい？","choices":["約1〜2メートル","約3〜4メートル","約6〜7メートル","約12〜15メートル"],"correctAnswer":"約6〜7メートル","hint":"身長の約3〜4倍もあります。お腹の中でぐるぐる折りたたまれています。","explanation":{"summary":"成人の小腸は約6〜7メートルで、消化管全体の約75%を占めます。","detail":"成人の小腸の長さは生きている状態で約3〜5メートル、死後に筋肉が弛緩すると約6〜7メートルに伸びます（教科書的には6〜7mが標準値として使われます）。身長の約3〜4倍に相当し、十二指腸（約25cm）、空腸（約2.5m）、回腸（約3.5m）の3つの部分に分けられます。\\n\\nこれだけ長い管がお腹の中に収まっているのは、腸間膜（mesentery）という扇のような膜で束ねられ、何層にも折りたたまれているからです。腸間膜は2017年にようやく「独立した臓器」として正式に認定されました。\\n\\n一方、大腸は約1.5メートルと短いですが、直径は小腸の約2〜3倍あります。消化管全体（口から肛門まで）の長さは約9メートルにもなります。","funFact":"小腸は約6〜7メートルもあるのにお腹に収まっている。折りたたみの達人！腸間膜という膜が扇のように束ねているから。","medicalNote":"おかもん先生：短腸症候群（手術で小腸を大量に切除した状態）では、残った腸が代償的に絨毛を大きくして吸収力を高める適応が起こります。人体の適応力は本当にすごいですね。","relatedQuestionIds":["digestive_010"]},"tags":["小腸","消化管","腸間膜"],"source":"Gray\'s Anatomy 42nd Edition; The Lancet Gastroenterology & Hepatology (Mesentery as organ, 2017)","timeLimitSeconds":30,"xpReward":30},{"id":"digestive_005","categorySlug":"digestive","type":"fill_in_blank","difficulty":3,"question":"肝臓で作られ、脂肪の消化を助ける黄緑色の液体を「＿＿」という。","correctAnswer":"胆汁","hint":"胆のうに貯められる液体で、「胆」の字がつきます。","explanation":{"summary":"胆汁（たんじゅう）は肝臓で1日約500〜1000ml作られ、脂肪を乳化して消化吸収を助けます。","detail":"胆汁（bile）は肝臓の肝細胞で1日に約500〜1000ml産生される黄緑色の消化液です。肝臓から胆管を通って胆のう（gallbladder）に送られ、約10倍に濃縮されて貯蔵されます。食事をすると胆のうが収縮し、胆汁が十二指腸に放出されます。\\n\\n胆汁の主な役割は脂肪の「乳化（emulsification）」です。油と水は通常混ざりませんが、胆汁に含まれる胆汁酸が界面活性剤（洗剤のような）として働き、脂肪を細かい粒にして水に分散させます。これにより消化酵素のリパーゼが脂肪に作用しやすくなります。\\n\\n胆汁の色は主にビリルビン（赤血球のヘモグロビンの分解産物）によるものです。腸内でビリルビンが変化して便の茶色い色の元になります。白っぽい便が出るときは、胆汁の流れが止まっている可能性があり要注意です。","funFact":"胆汁は天然の「洗剤」！食器用洗剤と同じ界面活性剤の原理で、脂肪を細かくして消化を助けている。","medicalNote":"おかもん先生：赤ちゃんの便が白っぽい（クリーム色やレモン色）場合は胆道閉鎖症の可能性があります。母子手帳の便色カードで毎日チェックすることが早期発見につながります。","relatedQuestionIds":["digestive_003"]},"tags":["胆汁","肝臓","脂肪消化","胆のう"],"source":"Guyton and Hall Textbook of Medical Physiology 14th Edition; Harper\'s Illustrated Biochemistry 31st Edition","timeLimitSeconds":30,"xpReward":30},{"id":"digestive_006","categorySlug":"digestive","type":"multiple_choice","difficulty":4,"question":"腸内細菌叢（腸内フローラ）の総重量は成人でおよそどのくらい？","choices":["約100グラム","約500グラム","約1.5〜2キログラム","約5キログラム"],"correctAnswer":"約1.5〜2キログラム","hint":"脳（約1.4kg）と同じくらいか、それ以上の重さがあります。","explanation":{"summary":"腸内細菌叢の総重量は約1.5〜2kgで、約1000種類・40兆個の細菌が棲んでいます。","detail":"成人の腸内には約1000種類、約40兆個の細菌が生息しており、その総重量は約1.5〜2kgにもなります（2016年のWeizmann研究所の研究では約0.2kgという推計もあり、測定法により差があります。ただし広く引用される値は1.5〜2kgです）。\\n\\n腸内細菌叢は「第二の臓器」「もう一つの脳」とも呼ばれ、消化吸収の補助だけでなく、免疫系の調節、ビタミン（K、B群）の合成、病原体からの防御、さらには脳の機能や気分にまで影響を与えることが分かっています（腸脳相関：gut-brain axis）。\\n\\nヒトの体の細胞は約37兆個ですが、腸内細菌は約40兆個。つまり数の上では細菌の方が多いのです。ヒトゲノムの遺伝子数は約2万個ですが、腸内細菌叢全体の遺伝子数（マイクロバイオーム）は約300〜500万個。私たちは細菌と共生する「超個体（superorganism）」とも言えるのです。","funFact":"あなたの体にいる細胞より腸内細菌の方が数が多い！37兆個の細胞に対して40兆個の細菌が腸に住んでいる。","medicalNote":"おかもん先生：赤ちゃんの腸内フローラは出生方法（経膣分娩 vs 帝王切開）や授乳方法（母乳 vs 人工乳）で大きく変わります。母乳に含まれるヒトミルクオリゴ糖は、善玉菌（ビフィズス菌）のエサになるんですよ。","relatedQuestionIds":["digestive_008"]},"tags":["腸内細菌","マイクロバイオーム","腸内フローラ","腸脳相関"],"source":"Sender et al., Cell (2016); Human Microbiome Project; Nature Reviews Gastroenterology & Hepatology","timeLimitSeconds":40,"xpReward":40},{"id":"digestive_007","categorySlug":"digestive","type":"multiple_choice","difficulty":4,"question":"膵臓（すいぞう）が分泌する消化液に含まれないものはどれ？","choices":["トリプシン（タンパク質分解酵素）","リパーゼ（脂肪分解酵素）","アミラーゼ（デンプン分解酵素）","ペプシン（タンパク質分解酵素）"],"correctAnswer":"ペプシン（タンパク質分解酵素）","hint":"ペプシンはある別の臓器で分泌される酵素です。その臓器は酸性環境です。","explanation":{"summary":"ペプシンは胃で分泌される酵素で、膵臓からは分泌されません。","detail":"膵臓（pancreas）は「消化のマルチプレイヤー」とも言える臓器で、三大栄養素すべてを分解する酵素を含む膵液を1日約1〜1.5リットル分泌します。トリプシン・キモトリプシン（タンパク質）、膵リパーゼ（脂肪）、膵アミラーゼ（デンプン）などが含まれます。\\n\\n一方、ペプシン（pepsin）は胃の主細胞（chief cell）から「ペプシノーゲン」という不活性型で分泌され、胃酸（pH 1〜2）の環境で活性化されるタンパク質分解酵素です。ペプシンは強酸性（pH 1.5〜2.5）でのみ働き、中性〜アルカリ性では失活します。\\n\\n膵臓は外分泌（消化酵素）と内分泌（インスリン・グルカゴンなどのホルモン）の二つの顔を持つ特異な臓器です。消化酵素は膵管を通じて十二指腸に放出され、ホルモンはランゲルハンス島から血中に直接分泌されます。","funFact":"膵臓は三大栄養素（糖質・脂質・タンパク質）すべてを消化する酵素を持つ唯一の臓器。さらに血糖値を調節するホルモンも出す二刀流！","medicalNote":"おかもん先生：膵臓の消化酵素は不活性型（前駆体）で分泌され、十二指腸で初めて活性化されます。もし膵臓内で活性化してしまうと「急性膵炎」という危険な病態になります。体の安全設計は本当によくできていますね。","relatedQuestionIds":["digestive_009"]},"tags":["膵臓","消化酵素","ペプシン","トリプシン"],"source":"Guyton and Hall Textbook of Medical Physiology 14th Edition; Ganong\'s Review of Medical Physiology 26th Edition","timeLimitSeconds":40,"xpReward":40},{"id":"digestive_008","categorySlug":"digestive","type":"true_false","difficulty":4,"question":"腸には脳に次いで2番目に多くの神経細胞があり、「第二の脳」と呼ばれている。","correctAnswer":"true","hint":"腸の壁の中には独自の神経ネットワークがあり、脳からの指令なしに独立して動けます。","explanation":{"summary":"腸管神経系には約5億個の神経細胞があり、脳に次ぐ規模の神経ネットワークを形成しています。","detail":"腸の壁の中には「腸管神経系（enteric nervous system: ENS）」と呼ばれる独立した神経ネットワークが存在し、約5億個の神経細胞（ニューロン）を含んでいます。これは脊髄の神経細胞数に匹敵し、脳・脊髄に次ぐ規模です。\\n\\n腸管神経系はアウエルバッハ神経叢（筋層間神経叢）とマイスナー神経叢（粘膜下神経叢）の二層構造から成り、消化管の蠕動運動、消化液の分泌、血流の調節などを脳からの指令なしに自律的に制御できます。\\n\\n驚くべきことに、腸はセロトニン（幸福ホルモン）の約95%を産生しています。腸と脳は迷走神経を通じて双方向に情報をやり取りしており（腸脳相関）、「緊張するとお腹が痛くなる」「腸内環境が気分に影響する」といった現象の科学的根拠になっています。","funFact":"幸福ホルモン「セロトニン」の95%は脳ではなく腸で作られている。腸が不調だと気分も落ちる科学的な理由がここに！","medicalNote":"おかもん先生：お子さんのストレスが腹痛として現れることが多いのは、腸脳相関の影響です。「お腹が痛い」は心のSOSかもしれません。心と体の両面からのケアが大切ですよ。","relatedQuestionIds":["digestive_006"]},"tags":["腸管神経系","第二の脳","セロトニン","腸脳相関"],"source":"Furness JB, The Enteric Nervous System (2006); Yano et al., Cell (2015); Gershon MD, The Second Brain (1998)","timeLimitSeconds":40,"xpReward":40},{"id":"digestive_009","categorySlug":"digestive","type":"fill_in_blank","difficulty":5,"question":"ピロリ菌（Helicobacter pylori）を発見し、胃潰瘍が感染症であることを証明するために自ら菌を飲んだオーストラリアの医師は＿＿である。","correctAnswer":"バリー・マーシャル","hint":"2005年にノーベル生理学・医学賞を受賞したオーストラリアの医師です。","explanation":{"summary":"バリー・マーシャル（Barry Marshall）は自らピロリ菌を飲んで胃炎を発症させ、胃潰瘍の原因が細菌であることを証明しました。","detail":"1982年、西オーストラリア大学のバリー・マーシャル医師とロビン・ウォレン病理学者は、胃の中から螺旋状の細菌（後にHelicobacter pyloriと命名）を発見しました。当時の医学界では「胃酸の強い胃の中で細菌は生きられない」「胃潰瘍はストレスが原因」というのが常識でした。\\n\\nマーシャルは動物実験がうまくいかなかったため、1984年に自らピロリ菌の培養液を飲むという大胆な自己実験を行いました。数日後に激しい胃炎を発症し、内視鏡で胃粘膜にピロリ菌がびっしり付着していることを確認。抗生物質で治療して回復しました。\\n\\nこの発見は、胃潰瘍の治療を「一生薬を飲み続ける」から「抗生物質で根治できる」に根本的に変え、2005年にマーシャルとウォレンはノーベル生理学・医学賞を受賞しました。医学の常識を覆した勇気ある自己実験として語り継がれています。","funFact":"「胃に細菌なんかいるわけない」という常識を覆すために、マーシャル医師は自分でピロリ菌を飲んだ。そしてノーベル賞を獲得！","medicalNote":"おかもん先生：日本人のピロリ菌感染率は50代以上で約40%、若い世代では大幅に減少しています。ピロリ菌は胃がんの最大のリスク因子です。お子さんが大きくなったら検査を検討してもよいでしょう。","relatedQuestionIds":["digestive_007"]},"tags":["ピロリ菌","胃潰瘍","ノーベル賞","医学史"],"source":"Marshall BJ, Warren JR, The Lancet (1984); Nobel Prize Committee (2005)","timeLimitSeconds":45,"xpReward":50},{"id":"digestive_010","categorySlug":"digestive","type":"multiple_choice","difficulty":5,"question":"腸管上皮細胞のターンオーバー（入れ替わり）の周期として最も近いものはどれ？","choices":["約1〜2日","約3〜5日","約2〜3週間","約2〜3か月"],"correctAnswer":"約3〜5日","hint":"体の中で最も速く入れ替わる組織のひとつです。抗がん剤の副作用で下痢が起きるのもこの速さが関係しています。","explanation":{"summary":"腸管上皮細胞は約3〜5日で完全に入れ替わり、人体で最も速いターンオーバーを持つ組織のひとつです。","detail":"腸管上皮細胞のターンオーバーは約3〜5日で、これは人体で最も速い細胞更新のひとつです。腸陰窩（クリプト）の底部にある幹細胞（LGR5陽性幹細胞）が絶えず分裂し、新しい細胞が絨毛の先端に向かって移動しながら分化し、先端から剥がれ落ちます。\\n\\n1日に脱落する腸管上皮細胞は推定約100億個にもなります。このエスカレーター式の細胞更新システムのおかげで、食物や細菌による損傷から常に回復できますが、同時に細胞分裂のエラーが蓄積するリスクもあり、大腸がんの発生母地になることがあります。\\n\\n抗がん剤治療中に下痢や口内炎が起きやすいのは、抗がん剤が分裂の速い細胞を標的にするため、腸管上皮や口腔粘膜がダメージを受けやすいからです。また、2009年に清水典明らが腸の幹細胞からミニ腸（腸オルガノイド）を培養する技術を確立し、再生医療に大きな道を拓きました。","funFact":"腸の表面は毎日100億個もの細胞が入れ替わっている。あなたの腸は5日前とは文字通り別物！","medicalNote":"おかもん先生：お子さんがウイルス性胃腸炎にかかっても比較的速く回復するのは、この速いターンオーバーのおかげです。脱水に注意しながら腸の回復力を信じて待ちましょう。","relatedQuestionIds":["digestive_004"]},"tags":["腸管上皮","ターンオーバー","幹細胞","再生医療"],"source":"Barker N et al., Nature (2007); Sato T et al., Nature (2009); Clevers H, Cell (2013)","timeLimitSeconds":45,"xpReward":50}]}'))},16171,e=>{e.v(JSON.parse('{"category":"nervous","version":"1.0.0","questions":[{"id":"nervous_001","categorySlug":"nervous","type":"true_false","difficulty":1,"question":"脳は体重の約2%しかないが、体が使うエネルギーの約20%を消費している。","correctAnswer":"true","hint":"脳は体の中で最もエネルギーを使う臓器のひとつです。","explanation":{"summary":"脳は体重の約2%（約1.4kg）ですが、全身のエネルギーの約20%を消費する「大食い臓器」です。","detail":"成人の脳は約1.4kgで体重の約2%にすぎませんが、安静時に体が消費するエネルギーの約20%を使います。これは主にニューロン（神経細胞）間のシナプス伝達とイオンポンプの維持に費やされます。\\n\\n脳のエネルギー源は主にブドウ糖（グルコース）です。脳は脂肪をエネルギー源としてほとんど利用できず、絶食が長期化すると肝臓が作るケトン体を代替燃料として使います。脳が1日に消費するブドウ糖は約120gで、角砂糖に換算すると約30個分に相当します。\\n\\n脳への血流が10秒途絶えただけで意識を失い、3〜5分で不可逆的な脳損傷が始まります。これは脳がエネルギーの貯蔵能力をほとんど持たず、常にリアルタイムの供給に依存しているためです。","funFact":"脳は体重のたった2%なのに、エネルギーの20%を独り占め。1日に角砂糖30個分のブドウ糖を消費する大食いの臓器！","medicalNote":"おかもん先生：赤ちゃんの脳は体重比でもっと大きく、体全体のエネルギーの約50%を脳が使います。だから授乳間隔が短い（頻回授乳が必要な）のは、脳にエネルギーを供給し続けるためでもあるんです。","relatedQuestionIds":["nervous_003"]},"tags":["脳","エネルギー","ブドウ糖"],"source":"Raichle ME, Gusnard DA, PNAS (2002); Mergenthaler P et al., Trends Neurosci (2013)","timeLimitSeconds":20,"xpReward":10},{"id":"nervous_002","categorySlug":"nervous","type":"multiple_choice","difficulty":1,"question":"体のバランスをとったり、運動を滑らかにする役割を担う脳の部分はどこ？","choices":["大脳","小脳","脳幹","視床"],"correctAnswer":"小脳","hint":"名前に「小さい」とついていますが、大脳の約10分の1の大きさで後頭部の下にあります。","explanation":{"summary":"小脳は後頭部の下に位置し、運動の協調・バランス・姿勢の維持に重要な役割を果たします。","detail":"小脳（cerebellum、ラテン語で「小さな脳」）は後頭部の下、脳幹の背側に位置し、脳全体の体積の約10%しかありませんが、脳のニューロンの約80%（約690億個）がここに集中しています。\\n\\n小脳の主な機能は運動の「微調整」です。大脳が「コップを取ろう」と命令を出すと、小脳がその動きをリアルタイムでモニタリングし、腕の角度、握る力、スピードを細かく調節します。小脳がなければ、手が震えたり、まっすぐ歩けなくなったりします（小脳失調）。\\n\\nまた、小脳は運動の学習にも重要です。自転車に乗る、箸を使う、楽器を弾くといった技能は、繰り返し練習することで小脳に「プログラム」として保存されます。「体が覚える」という表現は、科学的には「小脳が覚える」が正確です。","funFact":"「体が覚える」は科学的に言うと「小脳が覚える」。自転車に乗れるのも箸を使えるのも小脳のおかげ！","medicalNote":"おかもん先生：赤ちゃんの小脳は生後急速に発達します。お座り→ハイハイ→つかまり立ち→歩行という運動発達は、小脳の成熟と深く関わっています。焦らず見守ってあげてくださいね。","relatedQuestionIds":["nervous_004"]},"tags":["小脳","運動制御","バランス"],"source":"Kandel ER et al., Principles of Neural Science 6th Edition; Purves D et al., Neuroscience 6th Edition","timeLimitSeconds":20,"xpReward":10},{"id":"nervous_003","categorySlug":"nervous","type":"multiple_choice","difficulty":2,"question":"成人の脳にあるニューロン（神経細胞）の数はおよそどのくらい？","choices":["約100万個","約1億個","約860億個","約1兆個"],"correctAnswer":"約860億個","hint":"「千億」の桁です。天の川銀河の星の数に匹敵すると言われています。","explanation":{"summary":"成人の脳には約860億個のニューロンがあり、それぞれが数千のシナプスで他のニューロンとつながっています。","detail":"ブラジルの神経科学者スザーナ・エルクラーノ＝アウゼル（Suzana Herculano-Houzel）が2009年に等方性分画法（isotropic fractionator）という革新的な方法で正確に数えた結果、成人の脳には約860億個のニューロンがあることが分かりました。これは従来の「1000億個」という推定よりやや少ない値です。\\n\\nさらに驚くべきは、ニューロン同士をつなぐシナプス（接合部）の数です。1つのニューロンは平均約7000個のシナプスを持ち、脳全体では約100兆〜1000兆（1ペタ）個のシナプス結合が存在します。この膨大なネットワークが、思考・記憶・感情・創造性の物理的基盤です。\\n\\nちなみに、ニューロンと同数かそれ以上のグリア細胞（アストロサイト、オリゴデンドロサイト、ミクログリアなど）が存在し、ニューロンの栄養供給、絶縁、免疫防御などの裏方を担っています。","funFact":"脳のシナプスは100兆個以上。これは天の川銀河の星の数（約2000億個）の500倍。宇宙より複雑な構造があなたの頭の中に！","medicalNote":"おかもん先生：赤ちゃんの脳では1秒間に約100万個以上のシナプスが形成されます。3歳までにシナプスは成人の2倍に達し、その後使われないものが刈り込まれていきます（シナプス刈り込み）。豊かな経験が重要ですよ。","relatedQuestionIds":["nervous_001"]},"tags":["ニューロン","シナプス","脳","グリア細胞"],"source":"Herculano-Houzel S, PNAS (2009); Azevedo FA et al., J Comp Neurol (2009)","timeLimitSeconds":30,"xpReward":20},{"id":"nervous_004","categorySlug":"nervous","type":"fill_in_blank","difficulty":2,"question":"神経細胞から伸びる長い突起で、電気信号を遠くまで伝える部分を「＿＿」という。","correctAnswer":"軸索","hint":"「軸（じく）」に沿って信号が流れるケーブルのような構造です。英語では axon と言います。","explanation":{"summary":"軸索（じくさく、axon）はニューロンから伸びる長い突起で、電気信号（活動電位）を他のニューロンや筋肉に伝えます。","detail":"ニューロン（神経細胞）は大きく3つの部分から成ります。情報を受け取る「樹状突起（dendrite）」、細胞の本体である「細胞体（soma）」、そして情報を送り出す「軸索（axon）」です。\\n\\n軸索の長さはニューロンによって大きく異なり、脳内では数ミリメートルですが、脊髄から足先まで伸びる坐骨神経の軸索は約1メートルにもなります。キリンの場合は頸部の反回神経の軸索が数メートルに達します。\\n\\n多くの軸索は「ミエリン鞘（髄鞘）」というオリゴデンドロサイト（中枢）やシュワン細胞（末梢）が巻きつけた脂質の絶縁層で覆われています。ミエリン鞘がない部分（ランビエ絞輪）を信号がジャンプしながら伝わる「跳躍伝導」により、伝達速度は最大で秒速120メートル（時速約430km）に達します。","funFact":"最も速い神経の信号は秒速120メートル、時速430km。新幹線より速い電気信号があなたの体の中を走っている！","medicalNote":"おかもん先生：ミエリン鞘が壊れる多発性硬化症では、信号の伝達が遅くなったり途切れたりします。赤ちゃんのミエリン化は生後2年で急速に進み、これが運動・言語発達の基盤になります。","relatedQuestionIds":["nervous_002"]},"tags":["軸索","ニューロン","ミエリン鞘","活動電位"],"source":"Kandel ER et al., Principles of Neural Science 6th Edition; Bear MF et al., Neuroscience: Exploring the Brain 4th Edition","timeLimitSeconds":30,"xpReward":20},{"id":"nervous_005","categorySlug":"nervous","type":"multiple_choice","difficulty":3,"question":"「闘うか逃げるか反応（fight-or-flight response）」を引き起こすのは自律神経のどちらの系？","choices":["交感神経系","副交感神経系","体性神経系","腸管神経系"],"correctAnswer":"交感神経系","hint":"危険に遭遇したとき、心拍数を上げ、瞳孔を開き、体を臨戦態勢にする神経系です。","explanation":{"summary":"交感神経系は危険時に「闘うか逃げるか反応」を引き起こし、体を緊急モードに切り替えます。","detail":"自律神経系は「交感神経系（sympathetic）」と「副交感神経系（parasympathetic）」の2つから成り、主に無意識に内臓の機能を調節しています。\\n\\n**交感神経系**は、危険やストレスに直面したときに活性化されます。アドレナリン（エピネフリン）とノルアドレナリンを放出し、心拍数増加・血圧上昇・気管支拡張・瞳孔散大・消化活動の抑制・肝臓からのグルコース放出を引き起こします。これはサバンナでライオンに遭遇した祖先が瞬時に「戦う」か「逃げる」かの行動をとるために進化した仕組みです。\\n\\n**副交感神経系**は「休息と消化（rest and digest）」の系で、迷走神経を中心に心拍を落ち着かせ、消化を促進し、エネルギーを蓄積します。\\n\\n現代ではライオンに襲われることはありませんが、プレゼン前の緊張や怖い映画での動悸は同じ交感神経の反応です。この原始的な生存メカニズムが慢性的に活性化すると、ストレス関連疾患の原因になります。","funFact":"プレゼン前のドキドキは、10万年前の祖先がライオンから逃げるために進化させた「闘争・逃走反応」と同じ仕組み！","medicalNote":"おかもん先生：赤ちゃんが泣くとき、交感神経が活性化して心拍数が上がり顔が赤くなります。抱っこやスキンシップは副交感神経（迷走神経）を活性化させて安心させる効果がありますよ。","relatedQuestionIds":["nervous_007"]},"tags":["交感神経","副交感神経","自律神経","アドレナリン"],"source":"Kandel ER et al., Principles of Neural Science 6th Edition; Guyton and Hall Textbook of Medical Physiology 14th Edition","timeLimitSeconds":30,"xpReward":30},{"id":"nervous_006","categorySlug":"nervous","type":"true_false","difficulty":4,"question":"大人の脳は新しいニューロン（神経細胞）を作ることができない。","correctAnswer":"false","hint":"長い間「不可能」とされてきましたが、特定の部位では新しいニューロンが作られることが証明されています。","explanation":{"summary":"成人の脳でも海馬などの特定の部位では新しいニューロンが生まれています（成人神経新生）。","detail":"20世紀の神経科学では「成人の脳は新しいニューロンを作れない」というのが定説でした。しかし1998年、スウェーデンのエリクソン（Eriksson）らがヒトの海馬歯状回で成人神経新生（adult neurogenesis）が起きていることを初めて証明し、この常識を覆しました。\\n\\n海馬は記憶と学習に中心的な役割を果たす脳領域で、ここで新しく生まれるニューロンは空間記憶やパターン分離（似た記憶を区別する能力）に関与すると考えられています。また、嗅球（嗅覚を処理する部位）でも神経新生が確認されています。\\n\\nただし、成人神経新生の程度については議論が続いています。2018年のSorrellsらの研究では成人海馬での神経新生はごくわずかとする結果が出た一方、2019年のMoreno-Jimenezらは90歳でも神経新生が確認されたと報告しています。運動・豊かな環境・学習が神経新生を促進し、ストレス・加齢・うつ病が抑制するという知見は多くの研究で支持されています。","funFact":"「大人の脳は衰えるだけ」は間違い。運動すると海馬で新しいニューロンが生まれることが証明されている！","medicalNote":"おかもん先生：子どもの脳は成人以上に活発に神経新生が起きています。適度な運動、十分な睡眠、豊かな遊び環境がお子さんの脳の発達を最大限にサポートします。特に睡眠中に記憶の定着と脳の修復が行われますよ。","relatedQuestionIds":["nervous_003"]},"tags":["神経新生","海馬","可塑性","記憶"],"source":"Eriksson PS et al., Nature Medicine (1998); Moreno-Jimenez EP et al., Nature Medicine (2019); Sorrells SF et al., Nature (2018)","timeLimitSeconds":40,"xpReward":40},{"id":"nervous_007","categorySlug":"nervous","type":"multiple_choice","difficulty":4,"question":"痛みの信号を脳に伝える侵害受容線維のうち、「鋭い痛み（一次痛）」を伝えるのはどちらの線維？","choices":["Aδ（エーデルタ）線維","C線維","Aβ（エーベータ）線維","Aα（エーアルファ）線維"],"correctAnswer":"Aδ（エーデルタ）線維","hint":"この線維は薄いミエリン鞘を持ち、C線維より速く信号を伝えます。ピンと刺されたときの最初の「チクッ」がこの線維です。","explanation":{"summary":"Aδ線維は薄いミエリン鞘を持ち、鋭くて速い「一次痛」を伝えます。C線維は無髄で、鈍くじわじわした「二次痛」を伝えます。","detail":"痛みの信号を伝える感覚神経線維（侵害受容線維）には主に2種類あります：\\n\\n1. **Aδ線維**：直径1〜5μm、薄いミエリン鞘あり、伝導速度5〜30m/秒。ピンで刺されたり、熱いものに触れたときの「チクッ」「アチッ」という鋭い痛み（一次痛/fast pain）を伝えます。この速さのおかげで、危険から瞬時に手を引っ込める反射が可能になります。\\n\\n2. **C線維**：直径0.2〜1.5μm、ミエリン鞘なし（無髄線維）、伝導速度0.5〜2m/秒。一次痛に続いてじわじわと広がる鈍い痛み（二次痛/slow pain）を伝えます。この痛みは持続的で不快感が強く、炎症性の痛みや内臓痛の主体です。\\n\\nつまり、足の小指をぶつけたとき、最初の「ガンッ」という鋭い痛みはAδ線維、その後じわじわ広がる「ズキズキ」した痛みはC線維によるものです。この二段階の痛みを実感したことがある人は多いのではないでしょうか。","funFact":"足の小指をぶつけたとき、最初の「ガンッ」とその後の「ズキズキ」は別々の神経が伝えている。2種類の痛みを感じるのは正常な反応！","medicalNote":"おかもん先生：赤ちゃんも痛みを感じます（かつては「赤ちゃんは痛みを感じない」と誤解されていました）。ただしC線維系が優位で痛みの「局在」が曖昧なため、どこが痛いか表現できません。泣き方や行動から察してあげてくださいね。","relatedQuestionIds":["nervous_005"]},"tags":["痛覚","Aδ線維","C線維","侵害受容"],"source":"Kandel ER et al., Principles of Neural Science 6th Edition; Bear MF et al., Neuroscience: Exploring the Brain 4th Edition","timeLimitSeconds":40,"xpReward":40},{"id":"nervous_008","categorySlug":"nervous","type":"multiple_choice","difficulty":4,"question":"脳の老廃物を除去する、睡眠中に活性化するシステムの名前は？","choices":["リンパ系","グリンパティック系","門脈系","網内系"],"correctAnswer":"グリンパティック系","hint":"「グリア細胞」と「リンパ（lymphatic）」を組み合わせた造語です。","explanation":{"summary":"グリンパティック系（glymphatic system）は脳のグリア細胞を使った老廃物除去システムで、主に睡眠中に活性化されます。","detail":"グリンパティック系は2012年にデンマーク出身の神経科学者マイケン・ネーデルゴー（Maiken Nedergaard）らによって発見された、脳の老廃物除去システムです。「グリア（glia）」と「リンパティック（lymphatic）」を組み合わせた造語です。\\n\\n脳には通常のリンパ管がなく、老廃物をどう排出しているかは長年の謎でした。グリンパティック系では、脳脊髄液が動脈の周囲の空間（Virchow-Robin腔）を通って脳実質に入り込み、アストロサイト（星状グリア細胞）のアクアポリン4水チャネルを介して間質液と交換され、老廃物を洗い流します。\\n\\n驚くべきことに、このシステムは睡眠中に10倍以上活性化されます。睡眠中に脳細胞が約60%収縮して細胞間のスペースが広がり、洗浄液（脳脊髄液）が流れやすくなるためです。アルツハイマー病の原因物質とされるアミロイドβもグリンパティック系で除去されます。睡眠不足でアミロイドβが蓄積しやすくなることが複数の研究で示されています。","funFact":"睡眠中に脳は自分を「洗濯」している！脳細胞が60%縮んでスペースを作り、脳脊髄液で老廃物を洗い流す。寝ないと脳がゴミだらけに。","medicalNote":"おかもん先生：子どもに十分な睡眠が必要な理由の一つがグリンパティック系です。睡眠中に脳の老廃物が除去され、記憶が整理され、成長ホルモンも分泌されます。「寝る子は育つ」は科学的に正しいんです。","relatedQuestionIds":["nervous_006"]},"tags":["グリンパティック系","睡眠","アストロサイト","老廃物除去"],"source":"Iliff JJ et al., Science Translational Medicine (2012); Xie L et al., Science (2013); Nedergaard M, Science (2013)","timeLimitSeconds":40,"xpReward":40},{"id":"nervous_009","categorySlug":"nervous","type":"fill_in_blank","difficulty":5,"question":"ニューロン間の情報伝達で、シナプスの隙間に放出される化学物質を総称して「＿＿」という。","correctAnswer":"神経伝達物質","hint":"ドーパミン、セロトニン、アセチルコリンなどがこの物質の代表例です。","explanation":{"summary":"神経伝達物質（neurotransmitter）はシナプス間隙に放出される化学物質で、ニューロン間の情報伝達を担います。","detail":"神経伝達物質（neurotransmitter）は、シナプス前ニューロンの軸索末端にあるシナプス小胞に貯蔵されており、活動電位が到達するとカルシウムイオンの流入をきっかけにシナプス間隙（約20〜40nm）に放出されます。放出された神経伝達物質はシナプス後ニューロンの受容体に結合し、信号を化学的に伝えます。\\n\\n代表的な神経伝達物質とその役割：\\n- **アセチルコリン**：筋肉の収縮、記憶・学習\\n- **ドーパミン**：報酬・動機付け、運動制御（不足→パーキンソン病）\\n- **セロトニン**：気分・感情、睡眠・覚醒（不足→うつ病との関連）\\n- **GABA（γ-アミノ酪酸）**：脳の主要な抑制性伝達物質\\n- **グルタミン酸**：脳の主要な興奮性伝達物質、学習・記憶\\n- **ノルアドレナリン**：覚醒・注意・闘争逃走反応\\n\\n現在100種類以上の神経伝達物質が同定されています。抗うつ薬（SSRI）はセロトニンの再取り込みを阻害し、シナプス間隙のセロトニン濃度を高めることで効果を発揮します。パーキンソン病の治療薬レボドパはドーパミンの前駆体です。","funFact":"あなたの感情・記憶・やる気は、20ナノメートル（髪の毛の3000分の1）の隙間を飛び交う化学物質で決まっている！","medicalNote":"おかもん先生：ADHDのお子さんに処方されるメチルフェニデート（コンサータ等）は、ドーパミンとノルアドレナリンの再取り込みを阻害して前頭前皮質の機能を高めます。神経伝達物質のバランスを整える治療なので、正しく使えば安全ですよ。","relatedQuestionIds":["nervous_003","nervous_004"]},"tags":["神経伝達物質","シナプス","ドーパミン","セロトニン"],"source":"Kandel ER et al., Principles of Neural Science 6th Edition; Stahl SM, Stahl\'s Essential Psychopharmacology 5th Edition","timeLimitSeconds":45,"xpReward":50},{"id":"nervous_010","categorySlug":"nervous","type":"true_false","difficulty":5,"question":"人間は脳の10%しか使っていない。","correctAnswer":"false","hint":"これは非常に有名な「神話」です。脳イメージング研究の結果を考えてみましょう。","explanation":{"summary":"「脳の10%しか使っていない」は科学的根拠のない都市伝説です。脳の全領域が活発に使われています。","detail":"「人間は脳の10%しか使っていない」という説は、最も広く信じられている神経科学の都市伝説（neuromyth）のひとつです。2012年の調査では一般人の65%、教育者の約50%がこの神話を信じていると報告されました。\\n\\nしかし、fMRI（機能的磁気共鳴画像法）やPET（陽電子放射断層撮影）などの脳イメージング研究は、24時間の間にすべての脳領域が何らかの活動を示すことを明確に証明しています。単純な作業でも脳の多くの領域が協調して働きます。\\n\\n進化の観点からも10%説は不合理です。脳は体重の2%しかないのにエネルギーの20%を消費する「コスト高」な臓器です。もし90%が不要なら、自然選択によって脳はとっくに小さくなっているはずです。また、脳のどの部位が損傷しても何らかの機能障害が生じることも、全領域が使われている証拠です。\\n\\nこの神話の起源は諸説あり、アインシュタインの（誤って伝わった）発言、グリア細胞がニューロンの10倍あるという古い推定（現在は否定）、ウィリアム・ジェームズの「潜在能力を十分に使っていない」という比喩的表現などが候補に挙げられています。","funFact":"「脳の10%しか使っていない」は完全なウソ。24時間で脳の全領域が活動している。もし90%が不要なら進化で脳はとっくに小さくなっているはず！","medicalNote":"おかもん先生：この神話は「特別なサプリで脳の残り90%を活性化」といった詐欺的商品に悪用されることがあります。お子さんの能力を伸ばすのに必要なのは怪しいサプリではなく、十分な睡眠・運動・バランスの良い食事・豊かな遊びの経験です。","relatedQuestionIds":["nervous_001","nervous_006"]},"tags":["脳の神話","ニューロミス","fMRI","脳イメージング"],"source":"Beyerstein BL, Mind Myths (1999); Herculano-Houzel S, Do You Only Use 10% of Your Brain? (2004); Dekker S et al., Frontiers in Psychology (2012)","timeLimitSeconds":45,"xpReward":50}]}'))},46182,e=>{e.v(JSON.parse('{"category":"immune","version":"1.0.0","questions":[{"id":"immune_001","categorySlug":"immune","type":"multiple_choice","difficulty":1,"question":"体の中に入ってきたウイルスや細菌をやっつける仕組みを何というでしょう？","choices":["免疫（めんえき）","消化（しょうか）","呼吸（こきゅう）","代謝（たいしゃ）"],"correctAnswer":"免疫（めんえき）","hint":"「疫（えき）＝病気」を「免（まぬが）れる」と書くよ","explanation":{"summary":"免疫とは、体を病気から守るための防御システムのことです。","detail":"免疫（immunity）は、体の中に侵入してきたウイルス・細菌・寄生虫などの病原体を見つけ出し、攻撃して排除するシステムです。\\n\\n免疫には大きく分けて2種類あります。生まれつき備わっている「自然免疫」と、一度かかった病気を覚えて次から素早く対応できる「獲得免疫」です。予防接種（ワクチン）は、この獲得免疫の仕組みを利用しています。\\n\\n免疫システムは24時間365日休まず働いており、私たちが気づかないうちに毎日数千もの病原体を撃退しています。","funFact":"人間の体は毎日約5,000個のがん細胞が生まれているが、免疫細胞がそのほぼ全てを見つけて破壊している。","medicalNote":"おかもん先生：免疫は強すぎても弱すぎてもダメ。花粉症やアレルギーは免疫が「過剰に」反応している状態で、免疫不全は逆に弱すぎる状態です。バランスが大切なんですね。","relatedQuestionIds":["immune_002","immune_003"]},"tags":["免疫","基礎知識","防御"],"source":"標準免疫学 第4版（医学書院）","timeLimitSeconds":20,"xpReward":10},{"id":"immune_002","categorySlug":"immune","type":"true_false","difficulty":1,"question":"熱が出るのは、体が病原体と戦っている証拠である。","correctAnswer":"true","hint":"風邪をひいたとき、なぜ体が熱くなるか考えてみよう","explanation":{"summary":"発熱は、免疫システムが病原体と戦うために意図的に体温を上げている反応です。","detail":"体温が上がると、免疫細胞の働きが活発になります。具体的には、白血球の移動速度が上がり、病原体を食べる力（貪食能）が強まります。一方、多くのウイルスや細菌は37度以上の環境では増殖しにくくなります。\\n\\n発熱を引き起こすのは「サイトカイン」と呼ばれる物質です。免疫細胞が病原体を検知すると、インターロイキン-1（IL-1）やTNF-αなどのサイトカインを放出し、脳の視床下部にある体温調節中枢に「体温を上げろ」という指令を出します。\\n\\nただし、40度を超える高熱は体のタンパク質を傷つける危険があるため、適切な対応が必要です。","funFact":"体温が1度上がると、免疫力は最大5〜6倍に活性化するといわれている。逆に1度下がると約30%低下する。","medicalNote":"おかもん先生：37.5度程度の微熱なら、むやみに解熱剤を使わない方がいいこともあります。ただし、ぐったりしている・水分が取れない・高熱が続く場合は必ず受診してくださいね。","relatedQuestionIds":["immune_001","immune_006"]},"tags":["免疫","発熱","自然免疫","サイトカイン"],"source":"Ganong\'s Review of Medical Physiology 26th Edition","timeLimitSeconds":20,"xpReward":10},{"id":"immune_003","categorySlug":"immune","type":"multiple_choice","difficulty":2,"question":"体内に侵入した細菌をパクパク食べてくれる免疫細胞はどれ？","choices":["マクロファージ","赤血球","血小板","脂肪細胞"],"correctAnswer":"マクロファージ","hint":"「マクロ」は大きい、「ファージ」は食べるという意味のギリシャ語だよ","explanation":{"summary":"マクロファージは「大食細胞」とも呼ばれ、病原体を丸ごと飲み込んで消化する免疫細胞です。","detail":"マクロファージ（macrophage）は、血液中の単球（monocyte）が組織に入って成熟した細胞です。名前の通り「大きな（macro）食べる者（phage）」で、細菌・ウイルス・死んだ細胞・がん細胞などを次々と飲み込みます（貪食作用）。\\n\\n1個のマクロファージは、なんと100個以上の細菌を食べることができます。食べた後は分解し、その断片を他の免疫細胞（T細胞）に「こんな敵が来たよ」と提示します。これを「抗原提示」といい、獲得免疫を起動させる重要なスイッチです。\\n\\nマクロファージは全身のあらゆる組織に存在し、肝臓ではクッパー細胞、脳ではミクログリア、骨では破骨細胞と、場所によって異なる名前で呼ばれます。","funFact":"マクロファージは1882年にロシアの免疫学者メチニコフがヒトデの幼生にバラのトゲを刺す実験で発見した。この発見で彼はノーベル賞を受賞した。","medicalNote":"おかもん先生：マクロファージは免疫の「最前線の兵士」。自然免疫として真っ先に敵に立ち向かい、同時に獲得免疫チームへの連絡係も務める、頼れる存在です。","relatedQuestionIds":["immune_001","immune_004"]},"tags":["免疫","マクロファージ","貪食作用","自然免疫","白血球"],"source":"Janeway\'s Immunobiology 10th Edition","timeLimitSeconds":30,"xpReward":20},{"id":"immune_004","categorySlug":"immune","type":"true_false","difficulty":2,"question":"予防接種（ワクチン）は、弱めた病原体などを使って、免疫に「敵の顔」を覚えさせる仕組みである。","correctAnswer":"true","hint":"一度かかった病気に二度目はかかりにくいのと同じ原理だよ","explanation":{"summary":"ワクチンは、無害化した病原体の一部を体に入れることで、本物の感染なしに免疫記憶を作る技術です。","detail":"ワクチン（vaccine）は、弱毒化した病原体・不活化した病原体・病原体の一部（タンパク質やmRNA）を体内に投与し、獲得免疫に「この形の敵を覚えなさい」と学習させる方法です。\\n\\n接種後、B細胞が抗体を作り、T細胞が攻撃方法を学びます。さらに重要なのが「メモリー細胞（記憶細胞）」の形成です。メモリー細胞は何十年も体内に生き続け、本物の病原体が来たとき、初回より遥かに速く・大量に免疫反応を起こします。これを「免疫記憶」といいます。\\n\\n人類初のワクチンは1796年、英国の医師エドワード・ジェンナーが牛痘を用いて天然痘を予防したものです。vaccineの語源はラテン語の「vacca（牛）」です。","funFact":"ワクチンのおかげで天然痘は1980年に地球上から完全に根絶された。人類が根絶に成功した唯一の感染症である。","medicalNote":"おかもん先生：ワクチンは「予行演習」のようなもの。本番の感染前にリハーサルしておくことで、いざという時にすぐ対応できます。副反応は免疫が頑張って学習している証拠でもあります。","relatedQuestionIds":["immune_001","immune_005"]},"tags":["免疫","ワクチン","予防接種","獲得免疫","免疫記憶"],"source":"Plotkin\'s Vaccines 8th Edition","timeLimitSeconds":30,"xpReward":20},{"id":"immune_005","categorySlug":"immune","type":"fill_in_blank","difficulty":3,"question":"抗体を産生し、特定の病原体を狙い撃ちで攻撃する免疫細胞は「＿＿細胞」である。","correctAnswer":"B","hint":"この細胞は骨髄（Bone marrow）で成熟することが名前の由来だよ","explanation":{"summary":"B細胞（B lymphocyte）は、抗体を作り出す唯一の免疫細胞で、獲得免疫の中心的存在です。","detail":"B細胞は骨髄（Bone marrow）で作られ成熟する免疫細胞で、抗体（immunoglobulin）を産生できる唯一の細胞です。人間の体内には約100億個のB細胞が存在し、それぞれ異なる形の抗体を持っています。\\n\\nB細胞が病原体と出会い、T細胞からの「許可」を受けると、「形質細胞（plasma cell）」に変身し、1秒間に約2,000個もの抗体を放出するミサイル工場に変わります。放出された抗体は病原体に「目印」をつけ、マクロファージなどの免疫細胞が効率よく攻撃できるようにします。\\n\\n一部のB細胞は「メモリーB細胞」となり、何十年も体内で待機します。同じ病原体が再侵入した際、即座に大量の抗体を作り出すことで、私たちは同じ感染症に二度かかりにくくなるのです。","funFact":"B細胞は理論上10の11乗（1,000億）種類以上の異なる抗体を作り出す能力がある。地球上に存在するあらゆる病原体に対応できるライブラリを体内に持っている。","medicalNote":"おかもん先生：B細胞の名前は実は鶏の「ファブリキウス嚢（Bursa of Fabricius）」という器官に由来します。偶然にも人間では骨髄（Bone marrow）のBと一致したんです。医学の歴史って面白いですね。","relatedQuestionIds":["immune_004","immune_006"]},"tags":["免疫","B細胞","抗体","獲得免疫","形質細胞"],"source":"Molecular Biology of the Cell 7th Edition（Alberts et al.）","timeLimitSeconds":30,"xpReward":30},{"id":"immune_006","categorySlug":"immune","type":"multiple_choice","difficulty":4,"question":"HIV（ヒト免疫不全ウイルス）が主に攻撃する免疫細胞はどれ？","choices":["ヘルパーT細胞（CD4+T細胞）","キラーT細胞（CD8+T細胞）","B細胞","NK細胞"],"correctAnswer":"ヘルパーT細胞（CD4+T細胞）","hint":"免疫の「司令官」の役割を持つ細胞がターゲットになる","explanation":{"summary":"HIVはヘルパーT細胞（CD4+T細胞）を破壊することで、免疫システム全体を機能不全に陥れます。","detail":"ヘルパーT細胞はCD4というタンパク質を表面に持ち、免疫反応全体の「司令官」として機能します。B細胞への抗体産生指示、キラーT細胞の活性化、マクロファージの強化など、ほぼ全ての免疫応答を調整しています。\\n\\nHIVはこのCD4分子を「鍵穴」として利用し、ヘルパーT細胞に侵入します。ウイルスは細胞内で増殖し、最終的に細胞を破壊して飛び出し、次のヘルパーT細胞に感染します。健康な人のCD4+T細胞数は血液1μLあたり500〜1500個ですが、200個以下になるとAIDS（後天性免疫不全症候群）を発症します。\\n\\n司令官を失った免疫軍は統制を失い、通常は問題にならない弱い病原体（日和見感染症）にも対抗できなくなります。現在の抗レトロウイルス療法（ART）はHIVの増殖を抑え、CD4数を維持することで、感染者の寿命をほぼ一般と同等にまで延ばしています。","funFact":"HIVは1日に100億個以上のウイルス粒子を産生し、毎日10億個以上のCD4+T細胞を破壊する。人体はこれに対抗して毎日新しいCD4+T細胞を作り続けるが、やがて追いつけなくなる。","medicalNote":"おかもん先生：現代の治療で、HIV感染者はウイルス量を検出限界以下に抑えることが可能です。「U=U（Undetectable = Untransmittable）」、つまり検出限界以下なら他者への感染も起こらないことが科学的に証明されています。","relatedQuestionIds":["immune_005","immune_007"]},"tags":["免疫","HIV","AIDS","ヘルパーT細胞","CD4","感染症"],"source":"Harrison\'s Principles of Internal Medicine 21st Edition","timeLimitSeconds":40,"xpReward":40},{"id":"immune_007","categorySlug":"immune","type":"multiple_choice","difficulty":4,"question":"自然免疫において、ウイルスに感染した細胞を「抗体なし」で直接殺すことができる細胞はどれ？","choices":["NK細胞（ナチュラルキラー細胞）","好中球","マスト細胞","樹状細胞"],"correctAnswer":"NK細胞（ナチュラルキラー細胞）","hint":"「生まれつきの殺し屋」という意味の名前を持つ細胞だよ","explanation":{"summary":"NK細胞は、事前の学習なしにウイルス感染細胞やがん細胞を直接攻撃できる「生まれながらの殺し屋」です。","detail":"NK細胞（Natural Killer cell）は1975年に発見された自然免疫のリンパ球です。キラーT細胞が獲得免疫として抗原提示を経て活性化されるのに対し、NK細胞は「事前の感作なし」にウイルス感染細胞やがん細胞を認識して殺すことができます。\\n\\nNK細胞は正常な細胞が持つMHCクラスI分子（自分の証明書のようなもの）を監視しています。ウイルスに感染した細胞やがん細胞はこのMHCクラスIの発現が低下するため、NK細胞は「自分の証明書を出せない怪しいやつ」として攻撃します（missing-self仮説）。\\n\\n攻撃方法は、パーフォリンで標的細胞の膜に穴を開け、グランザイムという酵素を注入してアポトーシス（プログラム細胞死）を誘導するという、精密かつ致死的なものです。","funFact":"笑いはNK細胞を活性化する。大阪の研究で、お笑いを3時間観た後にNK細胞の活性が上昇したことが報告されている。「笑いは最良の薬」は科学的にも一理ある。","medicalNote":"おかもん先生：NK細胞は免疫の「即応部隊」。獲得免疫が準備を整える4〜7日の間、NK細胞が最前線で感染拡大を食い止めます。がん免疫療法でもNK細胞の活用が注目されています。","relatedQuestionIds":["immune_003","immune_006"]},"tags":["免疫","NK細胞","自然免疫","がん","パーフォリン"],"source":"Janeway\'s Immunobiology 10th Edition","timeLimitSeconds":40,"xpReward":40},{"id":"immune_008","categorySlug":"immune","type":"true_false","difficulty":4,"question":"母乳に含まれる抗体（IgA）は、赤ちゃんの腸を病原体から守るバリアとして機能する。","correctAnswer":"true","hint":"赤ちゃんはまだ自分で十分な抗体を作れないよ","explanation":{"summary":"母乳に豊富に含まれる分泌型IgA抗体は、新生児の未熟な腸管粘膜を病原体から防御する重要なバリアです。","detail":"新生児の免疫システムは未熟で、自力で十分な抗体を産生できるようになるまで数ヶ月かかります。この「免疫の空白期間」を埋めるのが、母乳に含まれる免疫成分です。\\n\\n特に初乳（出産後数日間の母乳）には分泌型IgA（sIgA）が非常に高濃度で含まれています。sIgAは赤ちゃんの腸管粘膜の表面にコーティングのように広がり、病原体が腸の細胞に付着・侵入するのを物理的にブロックします。胃酸で分解されにくい構造を持つため、経口摂取でも機能します。\\n\\n母乳にはIgA以外にも、ラクトフェリン（鉄を奪って細菌の増殖を抑制）、リゾチーム（細菌の細胞壁を破壊）、白血球（マクロファージやリンパ球）など、多彩な免疫成分が含まれています。母乳は「最初のワクチン」とも呼ばれます。","funFact":"母親が感染症にかかると、その病原体に対する抗体が24時間以内に母乳に出現する。母親の免疫システムがリアルタイムで赤ちゃんを守るオーダーメイド防御システムである。","medicalNote":"おかもん先生：母乳は赤ちゃんの免疫にとって素晴らしい贈り物です。ただし、母乳育児が難しい場合もあります。現代のミルクも非常に優れた栄養バランスで作られていますので、ご自身の状況に合った方法を選んでくださいね。","relatedQuestionIds":["immune_004","immune_005"]},"tags":["免疫","IgA","母乳","新生児","粘膜免疫"],"source":"Nelson Textbook of Pediatrics 22nd Edition","timeLimitSeconds":40,"xpReward":40},{"id":"immune_009","categorySlug":"immune","type":"fill_in_blank","difficulty":5,"question":"がん細胞が免疫から逃れるために悪用する「免疫チェックポイント」のブレーキを外す治療法は「免疫チェックポイント＿＿療法」と呼ばれ、2018年に本庶佑先生がノーベル賞を受賞した。","correctAnswer":"阻害","hint":"ブレーキを「さまたげる」「とめる」という意味の漢字2文字だよ","explanation":{"summary":"免疫チェックポイント阻害療法は、がん細胞が免疫のブレーキを悪用して逃れるのを防ぐ、革新的ながん治療法です。","detail":"免疫チェックポイントとは、免疫反応が過剰にならないよう「ブレーキ」をかける仕組みです。PD-1やCTLA-4といった分子がその代表です。がん細胞は巧みにこの仕組みを悪用し、PD-L1というタンパク質を表面に発現させてT細胞のPD-1に結合することで「攻撃するな」というシグナルを送ります。\\n\\n京都大学の本庶佑先生がPD-1を、テキサス大学のジェームズ・アリソン先生がCTLA-4の免疫抑制機能をそれぞれ発見し、これらのブレーキを外す抗体薬（ニボルマブ、イピリムマブなど）が開発されました。2018年、お二人はノーベル生理学・医学賞を共同受賞しています。\\n\\n従来治療が困難だった悪性黒色腫や肺がんなどで劇的な効果を示し、がん治療に革命をもたらしました。「がんの免疫からの逃亡を許さない」という発想の転換が、この治療法の核心です。","funFact":"本庶佑先生は「PD-1がブレーキだと分かった時、がんに効くはずだと確信した」と語っている。発見から薬の実用化まで約20年。基礎研究の粘り強さが人類を救った好例である。","medicalNote":"おかもん先生：免疫チェックポイント阻害療法は、免疫のブレーキを外すことで自己免疫様の副作用が出ることもあります。しかし、従来の化学療法とは全く異なるアプローチで、がん治療の歴史を塗り替えた画期的な発見です。","relatedQuestionIds":["immune_007","immune_005"]},"tags":["免疫","がん免疫療法","PD-1","CTLA-4","免疫チェックポイント","ノーベル賞","本庶佑"],"source":"The Nobel Prize in Physiology or Medicine 2018; Cell 2018; 175(2)","timeLimitSeconds":45,"xpReward":50},{"id":"immune_010","categorySlug":"immune","type":"multiple_choice","difficulty":5,"question":"自分自身の正常な組織を免疫が誤って攻撃する「自己免疫疾患」の発症を防ぐため、胸腺で行われるT細胞の選別プロセスを何という？","choices":["負の選択（negative selection）","正の選択（positive selection）","クローン増殖（clonal expansion）","クラススイッチ（class switching）"],"correctAnswer":"負の選択（negative selection）","hint":"自分の体に反応するT細胞を「消去」する仕組みだよ","explanation":{"summary":"負の選択とは、胸腺で自己反応性の危険なT細胞をアポトーシスで除去し、自己免疫疾患を防ぐ仕組みです。","detail":"T細胞は骨髄で生まれた後、胸腺（thymus）で厳しい「教育」を受けます。この教育には2段階あり、まず「正の選択」でMHC分子を認識できるT細胞だけが生き残り、次に「負の選択」で自己抗原に強く反応するT細胞がアポトーシス（プログラム細胞死）によって除去されます。\\n\\n驚くべきことに、胸腺に入ったT細胞の約95〜98%はこの選別で死滅します。わずか2〜5%の「合格者」だけが末梢に出て免疫の仕事に就くことができます。この厳格なプロセスが、自分の体を攻撃しない免疫システムを維持する「中枢性寛容」の根幹です。\\n\\n胸腺の上皮細胞はAIREという転写因子の働きで、通常は他の臓器でしか作られないタンパク質（インスリンや甲状腺ホルモンなど）をあえて発現し、これに反応するT細胞を見つけ出して除去します。AIREの遺伝子変異は多臓器の自己免疫疾患（APS-1）を引き起こします。","funFact":"胸腺は思春期をピークに年齢とともに萎縮し、脂肪に置き換わっていく。高齢者で自己免疫疾患や感染症が増えるのは、この「胸腺の退縮」が一因と考えられている。","medicalNote":"おかもん先生：胸腺は免疫の「教育機関」。ここでの厳しい選抜試験に落ちたT細胞は速やかに排除されます。この仕組みが破綻すると関節リウマチや1型糖尿病などの自己免疫疾患につながります。免疫の「自己と非自己の区別」は医学の根本的テーマです。","relatedQuestionIds":["immune_006","immune_009"]},"tags":["免疫","胸腺","T細胞","負の選択","自己寛容","AIRE","自己免疫疾患"],"source":"Robbins & Cotran Pathologic Basis of Disease 10th Edition","timeLimitSeconds":45,"xpReward":50}]}'))},299,e=>{e.v(JSON.parse('{"category":"sensory","version":"1.0.0","questions":[{"id":"sensory_001","categorySlug":"sensory","type":"multiple_choice","difficulty":1,"question":"人間が光を感じ取り、ものを「見る」ために使っている器官はどれ？","choices":["目（眼球）","耳（耳介）","鼻（鼻腔）","舌"],"correctAnswer":"目（眼球）","hint":"朝起きて最初に開けるところだよ","explanation":{"summary":"目（眼球）は光を受け取って電気信号に変換し、脳に「見える世界」を伝えるセンサーです。","detail":"目は直径約24mmの球体で、カメラと非常によく似た構造をしています。角膜と水晶体がレンズの役割を果たし、光を網膜上に集めます。網膜には約1億2,000万個の桿体細胞（暗いところで働く）と約600万個の錐体細胞（色を見分ける）が並んでおり、光を電気信号に変換します。\\n\\nこの電気信号は視神経を通って脳の後頭葉にある視覚野に届き、「ものが見える」という体験が生まれます。驚くべきことに、網膜に映る像は実際には上下左右が逆さまですが、脳が自動的に補正して正しい向きに「見せて」くれています。\\n\\n人間の目は約1,000万色を識別でき、暗い場所では星明り程度のわずかな光子でも感知できるほど高感度です。","funFact":"目は1時間に約900回、1日に約1万5,000〜2万回まばたきをしている。まばたき1回は約0.3秒で、1日の合計では約1.5時間も目を閉じている計算になる。","medicalNote":"おかもん先生：目は脳の一部が外に飛び出したような器官です。発生学的にも、網膜は脳と同じ神経管から分化します。「目は心の窓」というのは、科学的にも的を射た表現なんですよ。","relatedQuestionIds":["sensory_002","sensory_005"]},"tags":["感覚器","目","視覚","眼球","網膜"],"source":"Guyton and Hall Textbook of Medical Physiology 14th Edition","timeLimitSeconds":20,"xpReward":10},{"id":"sensory_002","categorySlug":"sensory","type":"true_false","difficulty":1,"question":"人間の耳は、音を聞くだけでなく、体のバランスを保つ役割も持っている。","correctAnswer":"true","hint":"目をつぶってグルグル回ると目が回るよね。それはどの器官のおかげ？","explanation":{"summary":"耳の奥にある内耳には、音を聞く蝸牛と体の平衡感覚を司る前庭・三半規管の両方が収まっています。","detail":"耳は外耳・中耳・内耳の3つに分かれています。外耳で集められた音は鼓膜を振動させ、中耳の3つの耳小骨（ツチ骨・キヌタ骨・アブミ骨）で約22倍に増幅されて内耳に伝わります。\\n\\n内耳にはカタツムリのような形の「蝸牛（かぎゅう）」があり、ここで音の振動が電気信号に変換されます。蝸牛の中には約15,000個の有毛細胞が並んでおり、振動で毛が揺れることで信号が生まれます。\\n\\nもう一つの重要な機能が平衡感覚です。三半規管（3つの半円形の管）は頭の回転を、耳石器（卵形嚢と球形嚢）は直線的な加速度と重力を検知します。これにより私たちは目をつぶっていても体の傾きや動きを感じ取ることができます。","funFact":"耳の中にあるアブミ骨は人体で最も小さい骨で、長さわずか約3mm。米粒よりも小さいこの骨が、音を正確に内耳に伝えるという精密な仕事をしている。","medicalNote":"おかもん先生：乗り物酔いは、目から入る視覚情報と内耳の平衡感覚情報がズレることで起こります。車の中で本を読むと酔いやすいのは、目は「止まっている」と感じているのに、内耳は「動いている」と感じるからです。","relatedQuestionIds":["sensory_001","sensory_007"]},"tags":["感覚器","耳","聴覚","平衡感覚","三半規管","内耳"],"source":"Gray\'s Anatomy 42nd Edition","timeLimitSeconds":20,"xpReward":10},{"id":"sensory_003","categorySlug":"sensory","type":"multiple_choice","difficulty":2,"question":"人間の舌が感じることができる基本的な味は何種類？","choices":["5種類","3種類","4種類","7種類"],"correctAnswer":"5種類","hint":"「甘い・辛い・苦い・酸っぱい」に、日本人が発見したもう1つを加えてみよう","explanation":{"summary":"人間の基本味は、甘味・塩味・酸味・苦味・うま味の5種類です。","detail":"舌の表面には約5,000〜10,000個の味蕾（みらい）があり、それぞれの味蕾には50〜100個の味細胞が含まれています。基本味は5つあります。\\n\\n1. **甘味** - エネルギー源（糖分）の存在を示す\\n2. **塩味** - ミネラル（電解質）の存在を示す\\n3. **酸味** - 腐敗や未熟な食物を警告する\\n4. **苦味** - 毒物の存在を警告する\\n5. **うま味** - タンパク質（アミノ酸）の存在を示す\\n\\nうま味は1908年に東京帝国大学の池田菊苗教授が昆布だしからグルタミン酸を発見して命名しました。長年「第5の味覚」として認められていませんでしたが、2000年に舌にうま味受容体（T1R1/T1R3）が発見され、正式に基本味として世界的に認知されました。「umami」はそのまま国際的な学術用語になっています。","funFact":"「辛い」は実は味覚ではなく、痛覚（三叉神経の刺激）である。唐辛子のカプサイシンは舌の温度受容体TRPV1を活性化し、43度以上の熱を感じた時と同じ信号を脳に送る。","medicalNote":"おかもん先生：苦味の受容体が最も種類が多い（約25種類）のは、自然界の毒物の多くが苦い味を持つため。子どもが苦い野菜を嫌がるのは、進化的には正しい防御反応なんです。成長とともに「これは安全」と学習して食べられるようになります。","relatedQuestionIds":["sensory_004","sensory_009"]},"tags":["感覚器","舌","味覚","うま味","味蕾"],"source":"Guyton and Hall Textbook of Medical Physiology 14th Edition","timeLimitSeconds":30,"xpReward":20},{"id":"sensory_004","categorySlug":"sensory","type":"true_false","difficulty":2,"question":"鼻がにおいを感じる仕組みは、においの分子が鼻の中の受容体にくっつくことで起こる。","correctAnswer":"true","hint":"鍵と鍵穴のような関係を想像してみよう","explanation":{"summary":"においの分子は鼻腔上部の嗅上皮にある嗅覚受容体に結合し、電気信号に変換されて脳に伝わります。","detail":"鼻腔の天井付近に、切手1枚分ほどの大きさの「嗅上皮（きゅうじょうひ）」があります。ここには約1,000万〜2,000万個の嗅覚ニューロンが密集しており、各ニューロンは1種類の嗅覚受容体を持っています。\\n\\n空気中を漂うにおい分子が嗅上皮の粘液に溶け込み、嗅覚受容体に結合すると、電気信号が発生します。この信号は嗅球（きゅうきゅう）を経て、脳の嗅覚皮質に伝わります。人間は約400種類の嗅覚受容体遺伝子を持ち、その組み合わせで約1兆種類のにおいを嗅ぎ分けられるとされています。\\n\\n嗅覚の特徴的な点は、五感の中で唯一、大脳新皮質を経由せずに直接、記憶（海馬）や感情（扁桃体）の中枢に接続していることです。特定のにおいを嗅いだ瞬間に昔の記憶が鮮明によみがえるのはこのためです。","funFact":"2004年にリチャード・アクセルとリンダ・バックは、嗅覚受容体の遺伝子ファミリー（約1,000個）を発見したことでノーベル生理学・医学賞を受賞した。人間のゲノムの約3%が嗅覚に使われている。","medicalNote":"おかもん先生：特定のにおいが昔の記憶を呼び覚ます現象を「プルースト効果」と呼びます。嗅覚は記憶と感情に直結しているため、認知症の早期発見にも嗅覚検査が活用されています。においがわかりにくくなったら要注意です。","relatedQuestionIds":["sensory_003","sensory_009"]},"tags":["感覚器","鼻","嗅覚","嗅覚受容体","嗅上皮"],"source":"The Nobel Prize in Physiology or Medicine 2004; Molecular Biology of the Cell 7th Edition","timeLimitSeconds":30,"xpReward":20},{"id":"sensory_005","categorySlug":"sensory","type":"fill_in_blank","difficulty":3,"question":"目の奥にある、光を電気信号に変換する薄い膜を「＿＿」という。","correctAnswer":"網膜","hint":"カメラでいうと「フィルム」にあたる部分で、「もう」で始まるよ","explanation":{"summary":"網膜（もうまく）は眼球の内側を覆う薄い神経組織で、光を電気信号に変換する「目のフィルム」です。","detail":"網膜（retina）は厚さわずか0.1〜0.5mmの薄い組織ですが、10層もの精密な神経回路で構成されています。光を受け取る視細胞は2種類あります。\\n\\n**桿体細胞（rod cell）** は約1億2,000万個あり、わずかな光でも反応する高感度センサーです。暗い場所での視覚を担当しますが、色は識別できません。**錐体細胞（cone cell）** は約600万個で、赤（L錐体）・緑（M錐体）・青（S錐体）の3種類があり、色覚を担います。\\n\\n網膜の中心にある「中心窩（ちゅうしんか）」は錐体細胞が最も密集しており、視力が最も鋭い部分です。文字を読んだり細かいものを見たりする時は、この直径約1.5mmの小さな領域を使っています。網膜で変換された電気信号は、約120万本の神経線維からなる視神経を通って脳に伝わります。","funFact":"網膜には盲点（もうてん）と呼ばれる、光を全く感じない部分がある。視神経が眼球から出る場所で視細胞がないため。しかし脳が周囲の情報で補完するので、普段は全く気づかない。","medicalNote":"おかもん先生：網膜剥離は、網膜が眼球の壁から剥がれる緊急疾患です。「飛蚊症が急に増えた」「視野の一部がカーテンのように暗い」という症状があったら、すぐ眼科を受診してください。早期治療で視力を守れます。","relatedQuestionIds":["sensory_001","sensory_006"]},"tags":["感覚器","目","網膜","視細胞","桿体","錐体"],"source":"Adler\'s Physiology of the Eye 12th Edition","timeLimitSeconds":30,"xpReward":30},{"id":"sensory_006","categorySlug":"sensory","type":"multiple_choice","difficulty":4,"question":"人間が色を見分けられるのは、網膜にある3種類の錐体細胞がそれぞれ異なる波長の光に反応するからである。この3種類が対応する色の組み合わせはどれ？","choices":["赤・緑・青","赤・黄・青","赤・緑・黄","赤・白・青"],"correctAnswer":"赤・緑・青","hint":"テレビやスマートフォンの画面はこの3色の光で全ての色を作っているよ","explanation":{"summary":"人間の色覚は、赤（長波長）・緑（中波長）・青（短波長）に感度のピークを持つ3種類の錐体細胞の信号の組み合わせで成り立っています。","detail":"人間の網膜には3種類の錐体細胞（cone cell）があり、それぞれ異なる波長の光に最も強く反応します。L錐体（赤、約560nm）、M錐体（緑、約530nm）、S錐体（青、約420nm）です。これを「三色説（Young-Helmholtz theory）」といいます。\\n\\n私たちが見る全ての色は、この3種類の錐体の興奮パターンの組み合わせで作られます。例えば黄色い光は、L錐体とM錐体の両方を刺激します。白色光は3種類全てを均等に刺激した状態です。テレビ画面がRGB（赤・緑・青）の3色で全色を再現できるのは、この原理に基づいています。\\n\\n色覚異常（色盲）は、これらの錐体のいずれかが欠損または機能異常を起こした状態です。最も多いのはL錐体とM錐体の遺伝子がX染色体上にあるため、男性の約8%、女性の約0.5%に見られる赤緑色覚異常です。","funFact":"シャコ（mantis shrimp）は16種類もの色受容体を持ち、紫外線や偏光も見える。しかし研究によると、シャコの色識別能力は人間より劣る可能性がある。受容体の数と色の識別力は必ずしも比例しない。","medicalNote":"おかもん先生：色覚異常は「色が見えない」のではなく「色の区別がつきにくい」状態です。信号機の赤と緑の区別が難しい場合がありますが、位置で判断するなど工夫で対応できます。「色覚多様性」として理解することが大切です。","relatedQuestionIds":["sensory_005","sensory_001"]},"tags":["感覚器","目","色覚","錐体細胞","三色説","RGB"],"source":"Principles of Neural Science 6th Edition（Kandel et al.）","timeLimitSeconds":40,"xpReward":40},{"id":"sensory_007","categorySlug":"sensory","type":"multiple_choice","difficulty":4,"question":"音の高さ（周波数）を脳が識別できるのは、蝸牛の中で高い音と低い音が異なる場所で感知されるからである。この仕組みを何という？","choices":["場所説（tonotopy）","周波数説","共鳴説","振幅説"],"correctAnswer":"場所説（tonotopy）","hint":"ピアノの鍵盤のように、場所ごとに反応する音が決まっている仕組みだよ","explanation":{"summary":"蝸牛の基底膜は場所によって異なる周波数に共振し、高い音は入口付近、低い音は奥で感知される「トノトピー（音の地図）」を形成しています。","detail":"蝸牛（cochlea）はカタツムリのように2回転半巻いた管で、引き伸ばすと約35mmの長さがあります。内部の基底膜（basilar membrane）は入口（基部）から奥（頂部）にかけて幅が広がり、硬さが変化しています。\\n\\n**基部（入口付近）** - 膜が狭く硬い → 高い周波数（高音）に共振\\n**頂部（奥）** - 膜が広く柔らかい → 低い周波数（低音）に共振\\n\\nこの「場所説」は1961年にノーベル生理学・医学賞を受賞したゲオルク・フォン・ベケシーの研究で実証されました。基底膜上の有毛細胞は、それぞれの位置に対応した周波数の音に最も強く反応し、この空間的なパターンが聴覚神経から脳の聴覚野に伝わります。聴覚野でもこの配列が保たれており、脳内に「音の地図（トノトピックマップ）」が形成されます。\\n\\n人間の可聴範囲は約20Hz〜20,000Hzで、会話は300Hz〜3,400Hzの範囲に集中しています。","funFact":"蝸牛の外有毛細胞は自ら伸び縮みして音を増幅する「蝸牛増幅器」として働く。この増幅機能のおかげで、人間は空気分子がわずか0.01nm（水素原子の直径の10分の1）しか動かないような微弱な音まで聞き取れる。","medicalNote":"おかもん先生：大音量の音楽やイヤホンで有毛細胞が損傷すると「騒音性難聴」になります。有毛細胞は一度壊れると再生しません。WHOは1日に85dB以上の音に8時間以上さらされると難聴リスクがあると警告しています。若いうちからの耳の保護が大切です。","relatedQuestionIds":["sensory_002","sensory_006"]},"tags":["感覚器","耳","聴覚","蝸牛","トノトピー","基底膜"],"source":"The Nobel Prize in Physiology or Medicine 1961; Principles of Neural Science 6th Edition","timeLimitSeconds":40,"xpReward":40},{"id":"sensory_008","categorySlug":"sensory","type":"true_false","difficulty":4,"question":"痛みを感じる「痛覚」の受容器は、特殊な形の終末器官を持たない自由神経終末である。","correctAnswer":"true","hint":"触覚にはパチニ小体やマイスナー小体など特殊な形があるけど、痛覚は？","explanation":{"summary":"痛覚受容器（侵害受容器）は、他の感覚受容器と異なり特殊な構造を持たず、神経線維の末端がむき出しの「自由神経終末」として存在します。","detail":"痛みを感知する侵害受容器（nociceptor）は、皮膚・筋肉・関節・内臓など全身に広く分布しています。触覚のパチニ小体やマイスナー小体のような特殊な被膜構造を持たず、神経線維の先端がそのまま組織の中に伸びている「自由神経終末（free nerve ending）」です。\\n\\n痛覚の信号は2種類の神経線維で伝えられます。Aδ線維は有髄神経で伝導速度が速く（5〜30m/秒）、鋭い痛み（一次痛）を伝えます。C線維は無髄神経で遅く（0.5〜2m/秒）、鈍い持続的な痛み（二次痛）を伝えます。足をぶつけた時、最初にズキッと感じ、その後ジワジワ痛くなるのはこの2種類の線維の速度差によるものです。\\n\\n侵害受容器は機械的刺激（切る・刺す）、温度刺激（熱い・冷たい）、化学的刺激（酸・炎症物質）など多種類の有害刺激に反応する「ポリモーダル受容器」が大多数です。","funFact":"脳そのものには痛覚がない。脳外科手術は患者が意識のある状態で行われることがある（覚醒下手術）。頭皮と頭蓋骨には痛覚があるが、脳実質を切っても痛みを感じない。","medicalNote":"おかもん先生：痛みは不快ですが、体を守る重要な警告システムです。先天性無痛症の患者さんは痛みを感じないため、骨折や火傷に気づかず重傷化することがあります。痛みの「ない世界」は実は非常に危険なのです。","relatedQuestionIds":["sensory_010","sensory_005"]},"tags":["感覚器","痛覚","侵害受容器","自由神経終末","Aδ線維","C線維"],"source":"Wall & Melzack\'s Textbook of Pain 6th Edition","timeLimitSeconds":40,"xpReward":40},{"id":"sensory_009","categorySlug":"sensory","type":"fill_in_blank","difficulty":5,"question":"特定のにおいを嗅いだ瞬間に昔の記憶が鮮明によみがえる現象を、フランスの作家の名前にちなんで「＿＿効果」という。","correctAnswer":"プルースト","hint":"『失われた時を求めて』でマドレーヌの香りから記憶が蘇るシーンが有名なフランス人作家だよ","explanation":{"summary":"プルースト効果は、においが記憶や感情を鮮明に呼び起こす現象で、嗅覚と脳の記憶・感情中枢が直接つながっていることに起因します。","detail":"プルースト効果（Proustian effect）は、フランスの作家マルセル・プルーストの小説『失われた時を求めて』に登場する、マドレーヌを紅茶に浸した香りから幼少期の記憶が鮮明に蘇るシーンに由来します。\\n\\n神経科学的にこの現象が説明できます。五感の中で嗅覚だけが、大脳新皮質（意識的な処理を行う領域）を経由せずに、直接「扁桃体（感情の中枢）」と「海馬（記憶の中枢）」に信号を送ります。視覚や聴覚は視床を経由してから大脳皮質に到達するのに対し、嗅覚は嗅球から直接これらの辺縁系に接続しているのです。\\n\\nfMRI研究では、においによって誘発された記憶は、言葉や画像によって誘発された記憶よりも感情的に鮮明で、幼少期の古い記憶を呼び起こす傾向が強いことが示されています。嗅覚は進化的に最も古い感覚であり、記憶・感情システムとの密接な結合はその名残です。","funFact":"嗅覚が衰えることはアルツハイマー病の最も早い兆候の一つで、記憶障害が現れる10年以上前から嗅覚低下が始まることがある。「においテスト」は認知症の早期スクリーニングに活用されている。","medicalNote":"おかもん先生：プルースト効果は、認知症ケアの「回想法」にも応用されています。患者さんの若い頃のにおい（畳、お線香、特定の料理など）を嗅いでもらうことで、失われかけた記憶や感情が一時的に蘇ることがあります。嗅覚と記憶の深い結びつきが治療に活きるのです。","relatedQuestionIds":["sensory_004","sensory_003"]},"tags":["感覚器","嗅覚","記憶","プルースト効果","扁桃体","海馬","辺縁系"],"source":"Principles of Neural Science 6th Edition（Kandel et al.）; Chemical Senses 2014; 39(1)","timeLimitSeconds":45,"xpReward":50},{"id":"sensory_010","categorySlug":"sensory","type":"multiple_choice","difficulty":5,"question":"「ゲート・コントロール理論」によれば、痛みの信号は脊髄で制御される。痛い場所をさするとラクになるのは、触覚の太い神経線維が「門」を閉じて痛みの伝達を抑制するからである。この理論を提唱したのは誰？","choices":["メルザックとウォール","ペンフィールドとラスムッセン","ヘルムホルツとヤング","ベケシーとフレッチャー"],"correctAnswer":"メルザックとウォール","hint":"この理論は1965年に発表され、「門（ゲート）」という比喩が使われているよ","explanation":{"summary":"ゲート・コントロール理論は、脊髄に痛みの「門」があり、触覚などの非痛覚信号がこの門を閉じることで痛みを抑制できるという画期的な理論です。","detail":"1965年にカナダの心理学者ロナルド・メルザック（Ronald Melzack）とイギリスの神経科学者パトリック・ウォール（Patrick Wall）が発表したゲート・コントロール理論は、痛みの理解を根本から変えた画期的な理論です。\\n\\n理論の核心は、脊髄後角に痛み信号の「門（gate）」があるという考えです。痛覚を伝える細い神経線維（C線維やAδ線維）の信号は門を「開け」、触覚を伝える太い神経線維（Aβ線維）の信号は門を「閉じる」作用があります。痛い場所をさすると痛みが和らぐのは、触覚のAβ線維が門を閉じ、痛み信号の脳への伝達を抑制するためです。\\n\\nこの理論はTENS（経皮的電気神経刺激）や鍼治療など、多くの疼痛治療法の理論的基盤となりました。また、心理的要因（注意・不安・期待など）も門の開閉に影響を与えることを示し、痛みが単なる物理的現象ではなく心理社会的要因を含む複合体験であることを明らかにしました。","funFact":"メルザックは後に「痛みのニューロマトリクス理論」を提唱し、幻肢痛（切断された手足が痛む現象）を説明した。脳内に体の地図（ニューロマトリクス）が存在し、実際の手足がなくても痛みの体験を生み出せるという理論である。","medicalNote":"おかもん先生：「痛いの痛いの飛んでいけ」は科学的に正しいんです。さすったり、吹いたりする触覚刺激がゲートを閉じて痛みを抑える。また、親の安心させる声（心理的要因）も門を閉じる方向に作用します。子どもへの接し方として理にかなっています。","relatedQuestionIds":["sensory_008","sensory_002"]},"tags":["感覚器","痛覚","ゲートコントロール理論","メルザック","ウォール","脊髄","疼痛"],"source":"Science 1965; 150(3699): 971-979; Wall & Melzack\'s Textbook of Pain 6th Edition","timeLimitSeconds":45,"xpReward":50}]}'))},21202,e=>{e.v(JSON.parse('{"category":"endocrine","version":"1.0.0","questions":[{"id":"endocrine_001","categorySlug":"endocrine","type":"multiple_choice","difficulty":1,"question":"「インスリン」というホルモンを分泌する臓器はどれ？","choices":["肝臓","すい臓（膵臓）","腎臓","脾臓"],"correctAnswer":"すい臓（膵臓）","hint":"おなかの奥にある、消化液も出す臓器だよ","explanation":{"summary":"インスリンは膵臓のランゲルハンス島β細胞から分泌される血糖値を下げる唯一のホルモンです。","detail":"膵臓（すいぞう）は胃の裏側にある約15cmの臓器で、消化酵素を出す「外分泌」と、ホルモンを出す「内分泌」の二刀流です。内分泌を担うのが**ランゲルハンス島**と呼ばれる細胞の集まりで、膵臓全体の約1〜2%しかありません。\\n\\nランゲルハンス島にはα細胞（グルカゴン分泌）、β細胞（インスリン分泌）、δ細胞（ソマトスタチン分泌）などがあり、血糖値の精密なコントロールを行っています。インスリンは体内で**唯一血糖値を下げるホルモン**であり、このβ細胞が破壊されると1型糖尿病になります。","funFact":"ランゲルハンス島は膵臓に約100万個あるけど、全部集めても小指の先ほどの大きさしかない！それで全身の血糖値をコントロールしている。","medicalNote":"インスリンが発見されたのは1921年。それまで1型糖尿病は確実に命を落とす病気でした。発見者のバンティングとベストは、世界中の子どもたちの命を救った英雄です。","relatedQuestionIds":["endocrine_004"]},"tags":["インスリン","膵臓","血糖値","ランゲルハンス島"],"source":"Guyton and Hall Textbook of Medical Physiology, 14th Edition","timeLimitSeconds":20,"xpReward":10},{"id":"endocrine_002","categorySlug":"endocrine","type":"true_false","difficulty":1,"question":"成長ホルモン（Growth Hormone）は、子どもの時期だけでなく大人になっても分泌されている。","correctAnswer":"true","hint":"大人の体にも「修理」や「メンテナンス」が必要だよね？","explanation":{"summary":"成長ホルモンは生涯にわたって分泌され、大人では細胞の修復や代謝の維持に重要な役割を果たします。","detail":"成長ホルモン（GH）は脳の下垂体前葉から分泌されます。子どもの時期には骨や筋肉の成長を促進しますが、大人になっても分泌は続きます。成人における成長ホルモンの役割は、**細胞の修復・再生**、**脂肪の分解促進**、**筋肉量の維持**、**骨密度の維持**など多岐にわたります。\\n\\nただし分泌量は加齢とともに減少し、30歳以降は10年ごとに約14%ずつ低下していきます。この現象は**ソマトポーズ（somatopause）**と呼ばれ、加齢に伴う体脂肪の増加や筋力低下の一因とされています。\\n\\n成長ホルモンは特に**深い睡眠（徐波睡眠）**の時に多く分泌されるため、質の良い睡眠は大人にとっても重要です。","funFact":"「寝る子は育つ」は科学的に正しい！成長ホルモンの約70%は夜の深い睡眠中に分泌される。大人も夜ふかしすると体の修復が追いつかなくなる。","medicalNote":"成人の成長ホルモン分泌不全症は、疲労感・体脂肪増加・筋力低下・骨密度低下などの症状を引き起こします。診断されれば、ホルモン補充療法の対象になることがあります。","relatedQuestionIds":["endocrine_005"]},"tags":["成長ホルモン","下垂体","睡眠","加齢"],"source":"Williams Textbook of Endocrinology, 14th Edition","timeLimitSeconds":20,"xpReward":10},{"id":"endocrine_003","categorySlug":"endocrine","type":"multiple_choice","difficulty":2,"question":"ストレスを感じたとき、副腎から大量に分泌される「闘争・逃走ホルモン」はどれ？","choices":["セロトニン","アドレナリン（エピネフリン）","メラトニン","オキシトシン"],"correctAnswer":"アドレナリン（エピネフリン）","hint":"ジェットコースターに乗ったときのドキドキ、あのホルモンだよ","explanation":{"summary":"アドレナリンは副腎髄質から分泌され、危機的状況で心拍数・血圧を上げ、体を臨戦態勢にします。","detail":"副腎は腎臓の上に帽子のように乗っている小さな臓器で、外側の**副腎皮質**と内側の**副腎髄質**に分かれています。ストレス時に副腎髄質から分泌されるのが**アドレナリン（エピネフリン）**と**ノルアドレナリン（ノルエピネフリン）**です。\\n\\nアドレナリンが分泌されると、心拍数の増加、血圧上昇、気管支拡張、瞳孔散大、肝臓からのグルコース放出など、体を瞬時に「戦闘モード」に切り替えます。これは人類が野生動物から逃げるために進化した仕組みで、**fight-or-flight response（闘争・逃走反応）**と呼ばれます。\\n\\n現代社会ではクマに遭遇することはめったにありませんが、プレゼンや試験前にドキドキするのも同じメカニズムです。","funFact":"アドレナリンは高峰譲吉によって1901年に世界で初めて結晶化に成功したホルモン。「アドレナリン」の名は副腎（adrenal gland）に由来し、実は日本人の大発見！","medicalNote":"アナフィラキシーショック（重度のアレルギー反応）の第一選択薬はアドレナリンの筋肉注射です。エピペンとして知られ、血圧低下と気道狭窄を劇的に改善します。","relatedQuestionIds":["endocrine_006"]},"tags":["アドレナリン","副腎","ストレス","闘争逃走反応"],"source":"Ganong\'s Review of Medical Physiology, 26th Edition","timeLimitSeconds":30,"xpReward":20},{"id":"endocrine_004","categorySlug":"endocrine","type":"true_false","difficulty":3,"question":"甲状腺ホルモンは基礎代謝を調節しており、甲状腺機能が低下すると体重が増えやすくなる。","correctAnswer":"true","hint":"エネルギーの「燃焼エンジン」を制御しているホルモンだよ","explanation":{"summary":"甲状腺ホルモン（T3・T4）は全身の代謝速度を決める「マスターレギュレーター」で、不足すると代謝が低下し体重増加につながります。","detail":"甲状腺はのどぼとけの下にある蝶のような形の臓器で、**サイロキシン（T4）**と**トリヨードサイロニン（T3）**という2種類のホルモンを分泌します。これらは**ヨウ素**を原料として作られ、全身のほぼすべての細胞に作用します。\\n\\n甲状腺ホルモンの主な作用は、**基礎代謝率の調節**、**体温維持**、**心拍数の調節**、**消化管運動の促進**、**脳の発達（特に胎児・乳児期）**です。\\n\\n**甲状腺機能低下症（橋本病など）**になると、代謝が低下するため、体重増加、寒がり、便秘、倦怠感、皮膚の乾燥、むくみなどの症状が現れます。逆に**甲状腺機能亢進症（バセドウ病など）**では、代謝が過剰になり、体重減少、動悸、発汗過多、手の震えなどが起こります。","funFact":"甲状腺ホルモンを作るのに必要なヨウ素は、日本人は海藻（昆布・ワカメ）から十分に摂取できている。世界ではヨウ素欠乏が最大の予防可能な知的障害の原因！だから多くの国では食塩にヨウ素を添加している。","medicalNote":"新生児マススクリーニングで先天性甲状腺機能低下症（クレチン症）の早期発見が可能です。生後早期にホルモン補充を開始すれば、正常な発達が期待できます。日本では約3,000〜5,000人に1人の頻度です。","relatedQuestionIds":["endocrine_001"]},"tags":["甲状腺","基礎代謝","T3","T4","ヨウ素"],"source":"Harrison\'s Principles of Internal Medicine, 21st Edition","timeLimitSeconds":30,"xpReward":30},{"id":"endocrine_005","categorySlug":"endocrine","type":"fill_in_blank","difficulty":3,"question":"脳の視床下部のすぐ下にあり、「ホルモンの司令塔」と呼ばれる内分泌腺は＿＿である。","correctAnswer":"下垂体","hint":"脳からぶら下がるような形をしていて、英語では pituitary gland というよ","explanation":{"summary":"下垂体（脳下垂体）は脳の底部にある小さな臓器で、多数のホルモンを分泌して他の内分泌腺を制御する「マスター腺」です。","detail":"**下垂体（かすいたい）**は脳の底部、ちょうど両目の奥あたりに位置する**エンドウ豆ほどの大きさ（約1cm、約0.5g）**の臓器です。小さいながら**前葉**と**後葉**に分かれ、合計9種類以上のホルモンを分泌します。\\n\\n**前葉**から分泌されるホルモン：成長ホルモン（GH）、甲状腺刺激ホルモン（TSH）、副腎皮質刺激ホルモン（ACTH）、卵胞刺激ホルモン（FSH）、黄体形成ホルモン（LH）、プロラクチン（PRL）\\n\\n**後葉**から分泌されるホルモン：抗利尿ホルモン（ADH/バソプレシン）、オキシトシン\\n\\n下垂体は上位の**視床下部**からの指令を受け、それぞれのホルモンの分泌量を精密に調節しています。視床下部→下垂体→標的内分泌腺という階層構造を**内分泌軸（axis）**と呼びます。","funFact":"下垂体はエンドウ豆サイズなのに9種類以上のホルモンを作る超高性能工場。しかも「トルコ鞍（sella turcica）」という骨のくぼみに大切に守られている、体のVIP中のVIP！","medicalNote":"下垂体腫瘍は意外と多く、人口の約10〜20%に微小な下垂体腺腫があるとされています。多くは無症状ですが、大きくなると視野障害（視交叉の圧迫）やホルモン異常を引き起こすことがあります。","relatedQuestionIds":["endocrine_002"]},"tags":["下垂体","視床下部","ホルモン","脳"],"source":"Guyton and Hall Textbook of Medical Physiology, 14th Edition","timeLimitSeconds":30,"xpReward":30},{"id":"endocrine_006","categorySlug":"endocrine","type":"multiple_choice","difficulty":4,"question":"副腎皮質から分泌され、「ストレスホルモン」とも呼ばれるコルチゾールの原料となる物質はどれ？","choices":["ブドウ糖（グルコース）","アミノ酸（チロシン）","コレステロール","脂肪酸"],"correctAnswer":"コレステロール","hint":"「悪者」扱いされがちだけど、ホルモンの材料として不可欠な脂質だよ","explanation":{"summary":"コルチゾールを含むステロイドホルモンは、すべてコレステロールを出発物質として合成されます。","detail":"ステロイドホルモン（コルチゾール、アルドステロン、性ホルモンなど）はすべて**コレステロール**を原料として作られます。副腎皮質の細胞内で、コレステロールが複数の酵素反応を経て段階的に変換され、最終的にコルチゾールになります。\\n\\nコルチゾールの主な作用は、**血糖値の上昇（糖新生促進）**、**抗炎症作用**、**免疫抑制**、**脂肪分解**、**タンパク質分解**などです。朝に分泌が最も多く、夜に少なくなる**日内変動（サーカディアンリズム）**があります。\\n\\nコレステロールは「動脈硬化の原因」として悪者扱いされがちですが、実はステロイドホルモンの原料、細胞膜の構成成分、ビタミンDの前駆体、胆汁酸の原料として**生命維持に不可欠**な物質です。","funFact":"コレステロールは体内で必要量の約70〜80%が肝臓で合成されている。食事から摂る量はむしろ少数派。卵を食べるとコレステロールが上がるという説は、近年の研究で大幅に修正されている。","medicalNote":"コルチゾールが過剰に分泌される病態がクッシング症候群で、満月様顔貌・中心性肥満・赤色皮膚線条などが特徴的です。逆にコルチゾールが不足するアジソン病は、色素沈着・低血圧・倦怠感が主症状です。","relatedQuestionIds":["endocrine_003"]},"tags":["コルチゾール","副腎皮質","ステロイド","コレステロール"],"source":"Williams Textbook of Endocrinology, 14th Edition","timeLimitSeconds":40,"xpReward":40},{"id":"endocrine_007","categorySlug":"endocrine","type":"true_false","difficulty":4,"question":"オキシトシンは「愛情ホルモン」と呼ばれ、出産時の子宮収縮だけでなく、握手やハグなどの身体接触でも分泌される。","correctAnswer":"true","hint":"このホルモンは社会的な絆の形成にも深く関わっているよ","explanation":{"summary":"オキシトシンは分娩時の子宮収縮と授乳時の射乳反射に加え、スキンシップや社会的絆の形成でも分泌が増加します。","detail":"オキシトシンは視床下部で合成され、下垂体後葉から血中に分泌されるペプチドホルモンです。古典的には**分娩時の子宮収縮**と**授乳時の射乳反射（母乳を押し出す作用）**が主な機能として知られていました。\\n\\nしかし近年の研究で、オキシトシンの役割はそれだけにとどまらないことが明らかになっています。**ハグ、握手、マッサージ**などの身体接触、**目を見つめ合う**こと、さらには**ペットとの触れ合い**でもオキシトシンの分泌が増加することが報告されています。\\n\\nオキシトシンは信頼感や安心感を高め、ストレスホルモン（コルチゾール）の分泌を抑制する作用もあります。このため「**愛情ホルモン**」「**絆ホルモン**」「**抱擁ホルモン**」とも呼ばれています。","funFact":"犬と飼い主が見つめ合うと、双方のオキシトシン濃度が上昇することが日本の研究で発見された。人間と犬の絆は、親子の絆と同じホルモンで結ばれている！","medicalNote":"合成オキシトシン（ピトシン）は、分娩促進剤として産科で広く使用されています。陣痛の誘発・促進や、産後の子宮収縮（出血予防）に不可欠な薬剤です。投与量の管理が重要で、過剰投与は子宮破裂のリスクがあります。","relatedQuestionIds":["endocrine_005"]},"tags":["オキシトシン","愛情ホルモン","下垂体後葉","社会的絆"],"source":"Psychoneuroendocrinology, Uvnäs-Moberg K. (2015)","timeLimitSeconds":40,"xpReward":40},{"id":"endocrine_008","categorySlug":"endocrine","type":"multiple_choice","difficulty":4,"question":"血液中のカルシウム濃度が低下したとき、骨からカルシウムを動員して血中濃度を上げるホルモンを分泌するのはどの臓器？","choices":["甲状腺","副甲状腺（上皮小体）","副腎","膵臓"],"correctAnswer":"副甲状腺（上皮小体）","hint":"甲状腺の「裏側」にくっついている、米粒大の小さな臓器だよ","explanation":{"summary":"副甲状腺（上皮小体）は副甲状腺ホルモン（PTH）を分泌し、骨からカルシウムを溶出させ、腎臓でのカルシウム再吸収を促進して血中カルシウム濃度を上昇させます。","detail":"**副甲状腺（ふくこうじょうせん）**は甲状腺の裏側に4個ある米粒大（約5mm）の小さな臓器です。ここから分泌される**副甲状腺ホルモン（PTH：parathyroid hormone）**は、血中カルシウム濃度の維持において最も重要なホルモンです。\\n\\nPTHの作用は3つのターゲットに及びます：\\n1. **骨**：破骨細胞を活性化し、骨からカルシウムとリンを血中に放出\\n2. **腎臓**：尿中へのカルシウム排泄を抑制（再吸収促進）、リンの排泄を促進、活性型ビタミンDの産生を促進\\n3. **腸管**（間接的）：活性型ビタミンDを介してカルシウムの吸収を促進\\n\\nカルシウムは心臓の拍動、筋肉の収縮、神経の伝達に不可欠なため、血中濃度は**8.5〜10.5 mg/dL**の狭い範囲に厳密に維持されています。","funFact":"カルシウムの99%は骨と歯にあり、血液中にはわずか1%。でもこの1%が心臓を動かし、筋肉を収縮させ、神経を伝達させている。副甲状腺はこの1%を死守するための番人！","medicalNote":"甲状腺手術の際に副甲状腺を誤って摘出・損傷すると、術後に低カルシウム血症を引き起こし、テタニー（手足の筋痙攣）が起こることがあります。外科医は手術中に副甲状腺を慎重に温存する必要があります。","relatedQuestionIds":["endocrine_004"]},"tags":["副甲状腺","カルシウム","PTH","骨代謝"],"source":"Williams Textbook of Endocrinology, 14th Edition","timeLimitSeconds":40,"xpReward":40},{"id":"endocrine_009","categorySlug":"endocrine","type":"fill_in_blank","difficulty":5,"question":"内分泌系のフィードバック機構において、標的臓器のホルモンが上位の視床下部や下垂体に作用して分泌を抑制する仕組みを＿＿フィードバックという。","correctAnswer":"ネガティブ","hint":"「抑制する」方向のフィードバックだから、ポジティブの反対だよ","explanation":{"summary":"ネガティブフィードバック（負のフィードバック）は、ホルモン濃度が上昇すると上位中枢からの刺激が抑制される仕組みで、内分泌系の恒常性維持の根幹です。","detail":"内分泌系の大部分は**ネガティブフィードバック（negative feedback）**によって制御されています。これはエアコンのサーモスタットに似た仕組みです。\\n\\n例えば甲状腺軸の場合：\\n1. 視床下部がTRH（甲状腺刺激ホルモン放出ホルモン）を分泌\\n2. 下垂体前葉がTSH（甲状腺刺激ホルモン）を分泌\\n3. 甲状腺がT3・T4（甲状腺ホルモン）を分泌\\n4. 血中のT3・T4が十分に上昇すると、視床下部と下垂体に作用してTRH・TSHの分泌を**抑制**\\n\\nこの仕組みにより、ホルモン濃度は常に適切な範囲に保たれます。\\n\\n一方、**ポジティブフィードバック（正のフィードバック）**は稀ですが、排卵直前のLHサージ（エストロゲンの急上昇がLH分泌をさらに促進）や、分娩時のオキシトシン分泌（子宮収縮が強まるほど分泌が増加）などで見られます。","funFact":"ネガティブフィードバックはエアコンの自動運転と同じ原理。設定温度に達したら冷房が弱まり、温度が上がったらまた強くなる。体内にはこのサーモスタットが無数にある！","medicalNote":"甲状腺機能低下症の診断では、T3・T4低値＋TSH高値というパターンが典型的です。これはネガティブフィードバックの理解そのもの：甲状腺ホルモンが少ないから、下垂体が「もっと出して！」とTSHを大量に分泌しているのです。","relatedQuestionIds":["endocrine_004","endocrine_005"]},"tags":["フィードバック","恒常性","視床下部-下垂体軸","ホメオスタシス"],"source":"Guyton and Hall Textbook of Medical Physiology, 14th Edition","timeLimitSeconds":45,"xpReward":50},{"id":"endocrine_010","categorySlug":"endocrine","type":"multiple_choice","difficulty":5,"question":"1型糖尿病の発症メカニズムとして最も正確な説明はどれ？","choices":["過食や運動不足によりインスリン抵抗性が生じる","自己免疫反応により膵臓のβ細胞が破壊される","膵臓のα細胞が過剰にグルカゴンを分泌する","肝臓でのインスリン分解が亢進する"],"correctAnswer":"自己免疫反応により膵臓のβ細胞が破壊される","hint":"体の免疫システムが「味方」を「敵」と間違えて攻撃してしまう病気だよ","explanation":{"summary":"1型糖尿病は、免疫システムが自分の膵臓β細胞を誤って攻撃・破壊する自己免疫疾患で、インスリンがほとんど分泌されなくなります。","detail":"1型糖尿病は**自己免疫疾患**です。本来、外敵から体を守るはずの免疫システムが、何らかの原因で膵臓ランゲルハンス島の**β細胞**を「異物」と認識して攻撃・破壊してしまいます。\\n\\nβ細胞の約80〜90%が破壊されると、インスリン分泌がほぼ停止し、血糖値のコントロールが不可能になります。発症は小児〜思春期に多いですが（以前は「小児糖尿病」と呼ばれていた）、成人発症もあります。\\n\\n診断時には血液中に**抗GAD抗体**、**抗IA-2抗体**、**抗インスリン抗体**などの自己抗体が検出されることが多く、これが自己免疫機序の証拠となります。\\n\\n2型糖尿病（インスリン抵抗性が主体）とは根本的にメカニズムが異なり、1型糖尿病は生涯にわたるインスリン注射が必要です。生活習慣とは無関係に発症するため、「自己責任」ではないことを理解することが重要です。","funFact":"1型糖尿病の治療に革命をもたらしたインスリンの発見（1921年）は、医学史上最も劇的なストーリーの一つ。昏睡状態の14歳の少年に世界初のインスリン注射が行われ、少年は奇跡的に回復した。","medicalNote":"近年、1型糖尿病の発症を遅らせる世界初の免疫療法薬テプリズマブ（teplizumab）がFDAに承認されました。発症リスクの高い方に対し、臨床的な1型糖尿病の発症を平均約2年遅らせることが示されています。","relatedQuestionIds":["endocrine_001"]},"tags":["1型糖尿病","自己免疫","β細胞","インスリン"],"source":"Harrison\'s Principles of Internal Medicine, 21st Edition","timeLimitSeconds":45,"xpReward":50}]}'))},37134,e=>{e.v(JSON.parse('{"category":"skin","version":"1.0.0","questions":[{"id":"skin_001","categorySlug":"skin","type":"multiple_choice","difficulty":1,"question":"人体で最も大きな臓器はどれ？","choices":["肝臓","小腸","皮膚","肺"],"correctAnswer":"皮膚","hint":"体の「外側」全体を覆っている臓器だよ","explanation":{"summary":"皮膚は成人で面積約1.6〜1.8平方メートル、重さ約3〜4kgにもなる人体最大の臓器です。","detail":"皮膚は体の表面全体を覆う臓器で、成人の場合**面積は約1.6〜1.8平方メートル**（畳約1枚分）、**重さは約3〜4kg**（体重の約16%）にもなります。これは肝臓（約1.2〜1.5kg）や脳（約1.3〜1.4kg）をはるかに上回ります。\\n\\n皮膚は外側から**表皮**、**真皮**、**皮下組織**の3層構造になっています。表皮の最も外側は角質層と呼ばれ、死んだ細胞が何層にも重なったバリアを形成しています。\\n\\n皮膚の役割は多岐にわたります：**物理的・化学的バリア**、**体温調節**、**感覚受容（触覚・圧覚・温度覚・痛覚）**、**紫外線防御**、**ビタミンD合成**、**免疫防御**、**水分の蒸発防止**などです。","funFact":"皮膚を全部広げると畳約1枚分の面積になる。しかも1平方センチメートルあたり約600個の汗腺、20本の血管、60個以上の感覚受容器がぎっしり詰まっている！","medicalNote":"重度の熱傷（やけど）で皮膚が広範囲に損傷すると、バリア機能が失われ、大量の水分喪失・感染症・体温調節障害など生命に関わる状態になります。熱傷の面積評価には「9の法則」が使われ、皮膚移植が救命に不可欠です。","relatedQuestionIds":["skin_003"]},"tags":["皮膚","臓器","面積","構造"],"source":"Gray\'s Anatomy, 42nd Edition","timeLimitSeconds":20,"xpReward":10},{"id":"skin_002","categorySlug":"skin","type":"true_false","difficulty":1,"question":"爪（つめ）は骨と同じ成分でできている。","correctAnswer":"false","hint":"爪の主成分は、髪の毛と同じタンパク質だよ","explanation":{"summary":"爪の主成分はケラチンというタンパク質で、カルシウムが主成分の骨とはまったく異なります。","detail":"爪の主成分は**ケラチン（keratin）**というタンパク質で、これは**髪の毛**や**皮膚の角質層**と同じ成分です。一方、骨の主成分は**リン酸カルシウム（ハイドロキシアパタイト）**とコラーゲンです。\\n\\n爪は皮膚の一部が変化したもので、**爪母（そうぼ：nail matrix）**と呼ばれる爪の根元の部分で常に新しいケラチンが作られ、前方に押し出されることで伸びていきます。\\n\\n手の爪は1日に約0.1mm、1か月で約3〜4mm伸びます。足の爪はその約半分の速度です。爪が完全に生え替わるには、手の爪で約6か月、足の爪で約1年かかります。","funFact":"爪が硬いのでカルシウムだと思われがちだけど、実は髪の毛と同じケラチン！牛乳をたくさん飲んでも爪は強くならない。爪を強くしたいなら、タンパク質やビオチン（ビタミンB7）が大事。","medicalNote":"爪の変化は全身疾患のサインになることがあります。スプーン状の爪（匙状爪）は鉄欠乏性貧血、ばち状指は慢性肺疾患や心疾患、爪の横溝（ボー線）は過去の重篤な全身疾患の痕跡を示唆します。","relatedQuestionIds":["skin_005"]},"tags":["爪","ケラチン","骨","タンパク質"],"source":"Fitzpatrick\'s Dermatology, 9th Edition","timeLimitSeconds":20,"xpReward":10},{"id":"skin_003","categorySlug":"skin","type":"multiple_choice","difficulty":2,"question":"日焼けで肌が黒くなるのは、皮膚のどの細胞が色素を増やすため？","choices":["線維芽細胞（fibroblast）","メラノサイト（melanocyte）","ランゲルハンス細胞","ケラチノサイト（keratinocyte）"],"correctAnswer":"メラノサイト（melanocyte）","hint":"「メラニン」という色素を作る専門の細胞だよ","explanation":{"summary":"メラノサイトは紫外線の刺激を受けるとメラニン色素を大量に産生し、周囲の表皮細胞に渡すことで肌を黒くし、DNAを紫外線から守ります。","detail":"**メラノサイト（色素細胞）**は表皮の基底層に存在し、**メラニン**という色素を産生する専門の細胞です。メラニンは**メラノソーム**という小胞の中で合成され、周囲のケラチノサイト（表皮の主要細胞）に受け渡されます。\\n\\n紫外線（UV）が皮膚に当たると、メラノサイトが活性化してメラニンの産生を増やします。メラニンは紫外線を吸収して散乱させる**天然のサンスクリーン**として機能し、細胞のDNAを紫外線による損傷から守ります。これが「日焼けで肌が黒くなる」メカニズムです。\\n\\n興味深いことに、メラノサイトの数は人種による差がほとんどありません。肌の色の違いは、メラノサイトが作るメラニンの**種類**（ユーメラニン＝黒褐色 vs フェオメラニン＝赤黄色）と**量**、そしてメラノソームの**大きさと分布パターン**の違いによるものです。","funFact":"1個のメラノサイトは周囲の約36個のケラチノサイトにメラニンを配っている。まるで1人のシェフが36人のお客さんに料理を配る「メラニンのレストラン」！","medicalNote":"メラノーマ（悪性黒色腫）はメラノサイトが悪性化した皮膚がんで、皮膚がんの中で最も悪性度が高いです。ほくろの変化（ABCDE基準：非対称性・辺縁不整・色の不均一・直径6mm以上・変化の経時的推移）に注意が必要です。","relatedQuestionIds":["skin_001"]},"tags":["メラノサイト","メラニン","日焼け","紫外線","色素"],"source":"Fitzpatrick\'s Dermatology, 9th Edition","timeLimitSeconds":30,"xpReward":20},{"id":"skin_004","categorySlug":"skin","type":"true_false","difficulty":3,"question":"人間の指紋のパターンは、一卵性双生児（双子）であっても完全に一致することはない。","correctAnswer":"true","hint":"指紋の形成には遺伝子だけでなく、子宮内での環境も影響するよ","explanation":{"summary":"指紋は遺伝子だけでなく胎児期の子宮内環境（羊水の流れ、指と羊膜の接触など）の影響を受けるため、遺伝子が同一の一卵性双生児でも完全に同じにはなりません。","detail":"指紋は妊娠10週頃から形成が始まり、約17週でほぼ完成します。その形成には遺伝的要因に加え、**胎児期の微小環境**が大きく影響します。具体的には、**羊水の流れ**、**指が触れる羊膜との接触圧**、**指の成長速度の微妙な左右差**などがランダムな揺らぎを生みます。\\n\\n一卵性双生児は遺伝子が100%同一ですが、子宮内での位置や羊膜との接触パターンがわずかに異なるため、指紋の全体的なパターン（渦巻き、蹄型、弓状）は似ていても、**細部の隆線（りゅうせん）パターンは一致しません**。\\n\\n指紋は一生変わらず（成長に伴い大きくはなる）、世界中に同じ指紋を持つ人は存在しないとされています。これが犯罪捜査での個人識別に使われる根拠です。","funFact":"コアラの指紋は人間と非常に似ていて、電子顕微鏡でも区別が難しいほど。でもコアラは霊長類ではなく有袋類。進化的にはまったく別の道を歩んだのに、同じ構造が生まれた「収斂進化」の傑作！","medicalNote":"一部の薬剤（特にカペシタビンなどの抗がん剤）は手足症候群を引き起こし、指紋が一時的に消失することがあります。入国審査で指紋認証ができなくなり問題になったケースが報告されています。","relatedQuestionIds":["skin_001"]},"tags":["指紋","双子","遺伝","個人識別","胎児発生"],"source":"Jain AK, et al. Pores and Ridges: High-Resolution Fingerprint Matching. IEEE Trans Pattern Anal Mach Intell. 2007","timeLimitSeconds":30,"xpReward":30},{"id":"skin_005","categorySlug":"skin","type":"fill_in_blank","difficulty":3,"question":"髪の毛や爪の主成分であり、皮膚の角質層を構成する硬いタンパク質の名前は＿＿である。","correctAnswer":"ケラチン","hint":"英語では keratin。「角質」の「角（ケラト）」が語源だよ","explanation":{"summary":"ケラチン（keratin）は硬い繊維状タンパク質で、髪の毛、爪、皮膚の角質層、動物の角やひづめの主成分です。","detail":"**ケラチン（keratin）**はギリシャ語の「keras（角）」に由来する名前を持つ繊維状タンパク質です。大きく分けて**硬ケラチン（α-ケラチン）**と**軟ケラチン**があり、髪の毛や爪には硬ケラチンが多く含まれます。\\n\\nケラチン分子はα-ヘリックス構造を持ち、複数の分子が撚り合わされてロープのような強固な構造を形成します。さらに、分子間を**ジスルフィド結合（S-S結合）**がつなぎ止めることで、非常に高い強度と耐久性を実現しています。\\n\\nパーマの原理はこのジスルフィド結合を利用しています。還元剤でS-S結合を一度切断し、髪を好みの形にした状態で酸化剤を使ってS-S結合を再形成させることで、新しい形を固定します。","funFact":"髪の毛1本は100gの重さに耐えられる。頭髪全体（約10万本）では理論上10トン、つまりアフリカゾウ2頭分を吊り下げられる計算！ケラチンの強さは鋼鉄に匹敵する。","medicalNote":"爪や皮膚に感染する白癬菌（はくせんきん）は、ケラチンを分解する酵素（ケラチナーゼ）を持っています。これが水虫（足白癬）や爪白癬の原因です。ケラチンを分解できる数少ない微生物の一つです。","relatedQuestionIds":["skin_002"]},"tags":["ケラチン","タンパク質","髪","爪","角質"],"source":"Molecular Biology of the Cell, 7th Edition (Alberts et al.)","timeLimitSeconds":30,"xpReward":30},{"id":"skin_006","categorySlug":"skin","type":"multiple_choice","difficulty":5,"question":"皮膚の表皮細胞（ケラチノサイト）が基底層で生まれてから角質層で垢として脱落するまでの周期は、正常な成人でおよそどのくらい？","choices":["約7日","約14日","約28日（約4週間）","約56日（約8週間）"],"correctAnswer":"約28日（約4週間）","hint":"女性の月経周期とほぼ同じ長さだよ","explanation":{"summary":"表皮細胞は基底層で分裂し、約14日で角質層に到達、さらに約14日で脱落するため、全体のターンオーバーは約28日（4週間）です。","detail":"表皮の最下層にある**基底層（stratum basale）**で幹細胞が分裂して新しいケラチノサイトが生まれます。この細胞は徐々に上方へ移動しながら分化し、**有棘層→顆粒層→角質層**へと変化していきます。\\n\\n基底層から角質層の最下部に到達するまでが約**14日**、角質層として機能した後に最表面から垢（あか）として脱落するまでがさらに約**14日**、合計約**28日**がターンオーバーの正常周期です。\\n\\nこの周期は加齢とともに延長し、40代では約40日、60代では約45〜60日程度になるとされています。ターンオーバーの遅延は、肌のくすみ、シミの定着、傷の治りの遅さの原因の一つです。\\n\\n逆に、**乾癬（かんせん）**ではターンオーバーが異常に加速し（約3〜4日）、未成熟な角質細胞が大量に蓄積して銀白色の鱗屑（りんせつ）を形成します。","funFact":"人間は一生の間に約18〜23kgの皮膚を脱ぎ捨てている計算になる。家のホコリの約70〜80%は人間の垢（剥がれた皮膚）だという研究もある！","medicalNote":"乾癬は、免疫異常による表皮のターンオーバー異常加速が本態です。かつてはステロイド外用が主体でしたが、近年は生物学的製剤（IL-17阻害薬、IL-23阻害薬など）の登場で治療成績が飛躍的に向上しています。","relatedQuestionIds":["skin_003","skin_005"]},"tags":["ターンオーバー","表皮","ケラチノサイト","角質","乾癬"],"source":"Fitzpatrick\'s Dermatology, 9th Edition","timeLimitSeconds":45,"xpReward":50},{"id":"skin_007","categorySlug":"skin","type":"multiple_choice","difficulty":4,"question":"皮膚が紫外線を受けて体内で合成するビタミンはどれ？","choices":["ビタミンA","ビタミンB12","ビタミンC","ビタミンD"],"correctAnswer":"ビタミンD","hint":"骨の健康に欠かせないビタミンで、「太陽のビタミン」とも呼ばれるよ","explanation":{"summary":"皮膚に紫外線B波（UVB）が当たると、コレステロールの一種である7-デヒドロコレステロールがビタミンD3に変換されます。","detail":"皮膚の表皮細胞には**7-デヒドロコレステロール（7-DHC）**というコレステロールの前駆体が含まれています。紫外線B波（UVB、波長280〜315nm）がこの物質に当たると、化学反応によって**プレビタミンD3**に変換され、さらに体温で**ビタミンD3（コレカルシフェロール）**になります。\\n\\nこのビタミンD3は血流に乗って肝臓で**25-ヒドロキシビタミンD**に、さらに腎臓で**1,25-ジヒドロキシビタミンD（活性型ビタミンD）**に変換されます。活性型ビタミンDは腸管でのカルシウム吸収を促進し、骨の形成と維持に不可欠です。\\n\\nビタミンDは食事だけでは十分な量を摂取することが難しく、皮膚での合成が重要な供給源です。しかし過度な紫外線防御（日焼け止め・室内生活）が続くとビタミンD不足に陥りやすくなります。","funFact":"ビタミンDは「ビタミン」と名付けられているけど、体内で合成できるので厳密にはビタミンではなくホルモンの前駆体。命名された当時はまだ体内合成が知られていなかった！","medicalNote":"日本人のビタミンD不足は深刻で、特に妊婦・高齢者・室内勤務者に多く見られます。近年、小児のくる病（ビタミンD欠乏による骨の変形）が再び増加傾向にあり、適度な日光浴の重要性が見直されています。","relatedQuestionIds":["skin_003"]},"tags":["ビタミンD","紫外線","骨","コレステロール","日光"],"source":"Holick MF. Vitamin D deficiency. N Engl J Med. 2007;357:266-81","timeLimitSeconds":40,"xpReward":40},{"id":"skin_008","categorySlug":"skin","type":"true_false","difficulty":4,"question":"皮膚の表面には常在菌（じょうざいきん）が生息しており、これらの菌は皮膚の健康を守る役割を果たしている。","correctAnswer":"true","hint":"腸内細菌と同じように、皮膚にも「味方の菌」がいるよ","explanation":{"summary":"皮膚には約1,000種以上の常在菌が存在し、病原菌の侵入を防ぎ、免疫を調節するなど皮膚の健康維持に重要な役割を果たしています。","detail":"人間の皮膚表面には**約1兆個**の微生物が生息しており、これを**皮膚マイクロバイオーム（skin microbiome）**と呼びます。主な常在菌には**表皮ブドウ球菌（Staphylococcus epidermidis）**、**アクネ菌（Cutibacterium acnes）**、**マラセチア属真菌**などがあります。\\n\\nこれらの常在菌は以下のような重要な役割を果たしています：\\n1. **競合排除**：有害な病原菌が定着するスペースと栄養を奪い、感染を防ぐ\\n2. **抗菌物質の産生**：バクテリオシンなどの抗菌ペプチドを分泌して病原菌を抑制\\n3. **免疫系の教育**：皮膚の免疫細胞と相互作用し、適切な免疫応答を維持\\n4. **皮膚バリアの強化**：脂質やセラミドの代謝を助け、バリア機能を補強\\n\\n過度な消毒や抗菌石けんの使用は常在菌のバランスを崩し、かえって皮膚トラブルを招くことがあります。","funFact":"皮膚1平方センチメートルあたり約100万個の細菌が住んでいる。脇の下は特に細菌が多く、熱帯雨林なみの生物多様性！でもそのほとんどは「味方」の菌。","medicalNote":"アトピー性皮膚炎の患者さんでは、皮膚常在菌のバランスが崩れ、黄色ブドウ球菌（Staphylococcus aureus）が異常に増殖していることが多いです。近年、皮膚マイクロバイオームの移植や調整による新しい治療アプローチが研究されています。","relatedQuestionIds":["skin_001"]},"tags":["常在菌","マイクロバイオーム","免疫","皮膚バリア"],"source":"Byrd AL, et al. The human skin microbiome. Nat Rev Microbiol. 2018;16:143-155","timeLimitSeconds":40,"xpReward":40},{"id":"skin_009","categorySlug":"skin","type":"multiple_choice","difficulty":4,"question":"傷が治る過程で、傷口を収縮させて閉じる役割を主に担う細胞はどれ？","choices":["マスト細胞（肥満細胞）","筋線維芽細胞（myofibroblast）","メルケル細胞","樹状細胞"],"correctAnswer":"筋線維芽細胞（myofibroblast）","hint":"「筋肉」の性質を持った「線維を作る細胞」の名前だよ","explanation":{"summary":"筋線維芽細胞はコラーゲンを産生しつつ筋肉のような収縮能力を持ち、傷口を物理的に引き寄せて閉じる創傷治癒の立役者です。","detail":"皮膚が傷つくと、体は**炎症期→増殖期→リモデリング期**という3段階の修復プロセスを開始します。増殖期に重要な役割を果たすのが**筋線維芽細胞（myofibroblast）**です。\\n\\n筋線維芽細胞は、通常の線維芽細胞が**TGF-β（形質転換成長因子β）**などのサイトカインの刺激を受けて分化したもので、2つの重要な機能を持ちます：\\n1. **コラーゲンの産生**：傷口を埋める新しい結合組織（肉芽組織）を形成\\n2. **収縮機能**：α-SMA（α平滑筋アクチン）を発現し、傷口の縁を物理的に引き寄せて閉じる\\n\\nこの収縮作用により、大きな傷口でも徐々に面積が縮小していきます。修復が完了すると筋線維芽細胞はアポトーシス（計画的細胞死）を起こして消失しますが、この過程がうまくいかないと**ケロイド**や**肥厚性瘢痕**の原因となります。","funFact":"筋線維芽細胞は「建設作業員」と「ウインチ操縦者」を兼ねる、傷の修復現場の最強マルチプレーヤー。コラーゲンを作りながら同時に傷口を引っ張って閉じる、一人二役！","medicalNote":"ケロイド体質は遺伝的要因が強く、有色人種に多い傾向があります。筋線維芽細胞が過剰に活性化し続けることが原因の一つで、ステロイド注射、圧迫療法、放射線治療などが行われますが、根治が難しい疾患です。","relatedQuestionIds":["skin_005"]},"tags":["創傷治癒","筋線維芽細胞","コラーゲン","瘢痕"],"source":"Gurtner GC, et al. Wound repair and regeneration. Nature. 2008;453:314-321","timeLimitSeconds":40,"xpReward":40},{"id":"skin_010","categorySlug":"skin","type":"fill_in_blank","difficulty":5,"question":"皮膚の表皮と真皮の間には＿＿膜という薄い構造があり、表皮細胞の足場となるとともに、物質の移動を制御している。","correctAnswer":"基底","hint":"表皮の最も「底」にある膜で、英語では basement membrane というよ","explanation":{"summary":"基底膜（basement membrane）は表皮と真皮の境界に存在する薄い細胞外マトリックスの層で、表皮の固定と物質透過の調節を担います。","detail":"**基底膜（きていまく）**は表皮と真皮の境界部に位置する**厚さ約50〜100nm**の非常に薄い構造で、主に**IV型コラーゲン**、**ラミニン**、**インテグリン**、**ヘミデスモソーム**などから構成されています。\\n\\n基底膜の主な機能は以下の通りです：\\n1. **構造的支持**：表皮細胞（ケラチノサイト）の足場として機能し、表皮を真皮にしっかりと固定\\n2. **物質の選択的透過**：栄養素や老廃物、シグナル分子の移動を制御するフィルター\\n3. **細胞の極性維持**：表皮細胞が正しい方向に分化・増殖するための情報を提供\\n4. **がん浸潤のバリア**：がん細胞が真皮へ浸潤することを物理的に阻止\\n\\n基底膜の構成タンパク質に対する自己抗体が産生されると、表皮と真皮の接着が失われ水疱（すいほう）が形成される**自己免疫性水疱症**（類天疱瘡など）を発症します。","funFact":"基底膜は厚さわずか0.05〜0.1マイクロメートル。人間の髪の毛の太さの1,000分の1以下なのに、表皮と真皮をしっかり接着し、がん細胞の侵入まで食い止めている超高機能フィルム！","medicalNote":"水疱性類天疱瘡（すいほうせいるいてんぽうそう）は高齢者に多い自己免疫疾患で、基底膜のBP180やBP230に対する自己抗体が原因です。全身に大型の緊満性水疱が出現し、ステロイドや免疫抑制剤による治療が必要です。","relatedQuestionIds":["skin_001","skin_009"]},"tags":["基底膜","表皮","真皮","コラーゲン","ラミニン"],"source":"Molecular Biology of the Cell, 7th Edition (Alberts et al.)","timeLimitSeconds":45,"xpReward":50}]}'))}]);